diff --git a/src/react-integration/__tests__/useCacheNew.tsx b/src/react-integration/__tests__/useCacheNew.tsx
new file mode 100644
index 0000000..beebf49
--- /dev/null
+++ b/src/react-integration/__tests__/useCacheNew.tsx
@@ -0,0 +1,91 @@
+import React, { useEffect } from 'react';
+import {
+  CoolerArticleResource,
+  PaginatedArticleResource,
+} from '../../__tests__/common';
+import { useCacheNew } from '../hooks';
+import makeRenderRestHook from '../../test/makeRenderRestHook';
+import { makeCacheProvider } from '../../test/providers';
+import { articlesPages, payload } from './fixtures';
+
+describe('useCacheNew()', () => {
+  let renderRestHook: ReturnType<typeof makeRenderRestHook>;
+  beforeEach(() => {
+    renderRestHook = makeRenderRestHook(makeCacheProvider);
+  });
+  afterEach(() => {
+    renderRestHook.cleanup();
+  });
+
+  it('should be null with empty state', () => {
+    const { result } = renderRestHook(() => {
+      return useCacheNew(CoolerArticleResource.detailShape(), payload);
+    }, {});
+    expect(result.current).toBe(null);
+  });
+
+  it('should select singles', () => {
+    const results = [
+      {
+        request: CoolerArticleResource.detailShape(),
+        params: payload,
+        result: payload,
+      },
+    ];
+    const { result } = renderRestHook(
+      () => {
+        return useCacheNew(CoolerArticleResource.detailShape(), payload);
+      },
+      { results },
+    );
+
+    expect(result.current).toBeTruthy();
+    expect(result.current && result.current.title).toBe(payload.title);
+  });
+
+  it('should select paginated results', () => {
+    const results = [
+      {
+        request: PaginatedArticleResource.listShape(),
+        params: {},
+        result: articlesPages,
+      },
+    ];
+    const { result } = renderRestHook(
+      () => {
+        return useCacheNew(PaginatedArticleResource.listShape(), {});
+      },
+      { results },
+    );
+    expect(result.current).toBeDefined();
+    if (!result.current) return;
+    expect(result.current.results.length).toBe(articlesPages.results.length);
+    expect(result.current.results[0]).toBeInstanceOf(PaginatedArticleResource);
+    expect(result.current.results).toMatchSnapshot();
+  });
+
+  it('should return identical value no matter how many re-renders', () => {
+    const results = [
+      {
+        request: PaginatedArticleResource.listShape(),
+        params: {},
+        result: articlesPages,
+      },
+    ];
+    const track = jest.fn();
+
+    const { rerender } = renderRestHook(
+      () => {
+        const articles = useCacheNew(PaginatedArticleResource.listShape(), {});
+        useEffect(track, [articles]);
+      },
+      { results },
+    );
+
+    expect(track.mock.calls.length).toBe(1);
+    for (let i = 0; i < 2; ++i) {
+      rerender();
+    }
+    expect(track.mock.calls.length).toBe(1);
+  });
+});

diff --git a/src/react-integration/__tests__/useResourceNew.tsx b/src/react-integration/__tests__/useResourceNew.tsx
new file mode 100644
index 0000000..8ce5f25
--- /dev/null
+++ b/src/react-integration/__tests__/useResourceNew.tsx
@@ -0,0 +1,361 @@
+import React, { Suspense, useEffect } from 'react';
+import { render } from '@testing-library/react';
+import nock from 'nock';
+import { normalize } from '../../resource';
+
+import { DispatchContext, StateContext } from '../context';
+import {
+  CoolerArticleResource,
+  UserResource,
+  InvalidIfStaleArticleResource,
+} from '../../__tests__/common';
+import { useResourceNew } from '../hooks';
+import makeRenderRestHook from '../../test/makeRenderRestHook';
+import { makeCacheProvider } from '../../test/providers';
+import mockInitialState from '../../test/mockState';
+import { payload, users, nested } from './fixtures';
+
+async function testDispatchFetch(
+  Component: React.FunctionComponent<any>,
+  payloads: any[],
+) {
+  const dispatch = jest.fn();
+  const tree = (
+    <DispatchContext.Provider value={dispatch}>
+      <Suspense fallback={null}>
+        <Component />
+      </Suspense>
+    </DispatchContext.Provider>
+  );
+  render(tree);
+  expect(dispatch).toHaveBeenCalled();
+  expect(dispatch.mock.calls.length).toBe(payloads.length);
+  let i = 0;
+  for (const call of dispatch.mock.calls) {
+    expect(call[0]).toMatchSnapshot();
+    const action = call[0];
+    const res = await action.payload();
+    expect(res).toEqual(payloads[i]);
+    i++;
+  }
+}
+
+function ArticleComponentTester({ invalidIfStale = false }) {
+  const resource = invalidIfStale
+    ? InvalidIfStaleArticleResource
+    : CoolerArticleResource;
+  const article = useResourceNew(resource.detailShape(), {
+    id: payload.id,
+  });
+  return (
+    <div>
+      <h3>{article.title}</h3>
+      <p>{article.content}</p>
+    </div>
+  );
+}
+
+describe('useResourceNewNew()', () => {
+  let renderRestHook: ReturnType<typeof makeRenderRestHook>;
+  const fbmock = jest.fn();
+
+  function Fallback() {
+    fbmock();
+    return null;
+  }
+
+  beforeEach(() => {
+    renderRestHook = makeRenderRestHook(makeCacheProvider);
+    nock('http://test.com')
+      .get(`/article-cooler/${payload.id}`)
+      .reply(200, payload);
+    nock('http://test.com')
+      .delete(`/article-cooler/${payload.id}`)
+      .reply(204, '');
+    nock('http://test.com')
+      .delete(`/article/${payload.id}`)
+      .reply(200, {});
+    nock('http://test.com')
+      .get(`/article-cooler/0`)
+      .reply(403, {});
+    nock('http://test.com')
+      .get(`/article-cooler/666`)
+      .reply(200, '');
+    nock('http://test.com')
+      .get(`/article-cooler/`)
+      .reply(200, nested);
+    nock('http://test.com')
+      .get(`/user/`)
+      .reply(200, users);
+  });
+  afterEach(() => {
+    nock.cleanAll();
+    renderRestHook.cleanup();
+  });
+
+  it('should dispatch an action that fetches', async () => {
+    await testDispatchFetch(ArticleComponentTester, [payload]);
+  });
+
+  it('should dispatch fetch when sent multiple arguments', async () => {
+    function MultiResourceTester() {
+      const [article, user] = useResourceNew(
+        [
+          CoolerArticleResource.detailShape(),
+          {
+            id: payload.id,
+          },
+        ],
+        [UserResource.listShape(), {}],
+      );
+      return null;
+    }
+    await testDispatchFetch(MultiResourceTester, [payload, users]);
+  });
+  it('should throw same promise until both resolve', async () => {
+    const renderRestHook = makeRenderRestHook(makeCacheProvider);
+    jest.useFakeTimers();
+    nock('http://test.com')
+      .get(`/article-cooler/${payload.id}`)
+      .delay(1000)
+      .reply(200, payload);
+    nock('http://test.com')
+      .get(`/user/`)
+      .delay(2000)
+      .reply(200, users);
+
+    function MultiResourceTester() {
+      try {
+        const [article, user] = useResourceNew(
+          [
+            CoolerArticleResource.detailShape(),
+            {
+              id: payload.id,
+            },
+          ],
+          [UserResource.listShape(), {}],
+        );
+        return article;
+      } catch (e) {
+        if (typeof e.then === 'function') {
+          return e;
+        } else {
+          // TODO: we're not handling suspense properly so react complains
+          // When upgrading test util we should be able to fix this as we'll suspense ourselves.
+          if (e.name === 'Invariant Violation') {
+            return null;
+          } else {
+            throw e;
+          }
+        }
+      }
+    }
+    const { rerender, result, waitForNextUpdate } = renderRestHook(
+      MultiResourceTester,
+    );
+    const firstPromise = result.current;
+    jest.advanceTimersByTime(50);
+    rerender();
+    expect(result.current).toBe(firstPromise);
+    jest.advanceTimersByTime(1000);
+    rerender();
+    expect(result.current).toBe(firstPromise);
+    jest.advanceTimersByTime(2000);
+    rerender();
+    expect(result.current).toBe(firstPromise);
+
+    // TODO: we're not handling suspense properly so react complains
+    // When upgrading test util we should be able to fix this as we'll suspense ourselves.
+    const oldError = console.error;
+    console.error = () => {};
+    jest.runAllTimers();
+    await result.current;
+    rerender();
+    expect(result.current).toBe(null);
+    // eslint-disable-next-line require-atomic-updates
+    console.error = oldError;
+  });
+  it('should NOT suspend if result already in cache and options.invalidIfStale is false', () => {
+    const state = mockInitialState([
+      {
+        request: CoolerArticleResource.detailShape(),
+        params: payload,
+        result: payload,
+      },
+    ]);
+
+    const tree = (
+      <StateContext.Provider value={state}>
+        <Suspense fallback={<Fallback />}>
+          <ArticleComponentTester />
+        </Suspense>
+      </StateContext.Provider>
+    );
+    const { getByText } = render(tree);
+    expect(fbmock).not.toBeCalled();
+    const title = getByText(payload.title);
+    expect(title).toBeDefined();
+    expect(title.tagName).toBe('H3');
+  });
+  it('should NOT suspend even when result is stale and options.invalidIfStale is false', () => {
+    const { entities, result } = normalize(
+      payload,
+      CoolerArticleResource.getEntitySchema(),
+    );
+    const fetchKey = CoolerArticleResource.detailShape().getFetchKey(payload);
+    const state = {
+      entities,
+      results: {
+        [fetchKey]: result,
+      },
+      meta: {
+        [fetchKey]: {
+          date: 0,
+          expiresAt: 0,
+        },
+      },
+    };
+
+    const tree = (
+      <StateContext.Provider value={state}>
+        <DispatchContext.Provider value={() => {}}>
+          <Suspense fallback={<Fallback />}>
+            <ArticleComponentTester />
+          </Suspense>{' '}
+        </DispatchContext.Provider>
+      </StateContext.Provider>
+    );
+    const { getByText } = render(tree);
+    expect(fbmock).not.toBeCalled();
+    const title = getByText(payload.title);
+    expect(title).toBeDefined();
+    expect(title.tagName).toBe('H3');
+  });
+  it('should NOT suspend if result is not stale and options.invalidIfStale is true', () => {
+    const { entities, result } = normalize(
+      payload,
+      InvalidIfStaleArticleResource.getEntitySchema(),
+    );
+    const fetchKey = InvalidIfStaleArticleResource.detailShape().getFetchKey(
+      payload,
+    );
+    const state = {
+      entities,
+      results: {
+        [fetchKey]: result,
+      },
+      meta: {
+        [fetchKey]: {
+          date: Infinity,
+          expiresAt: Infinity,
+        },
+      },
+    };
+
+    const tree = (
+      <StateContext.Provider value={state}>
+        <Suspense fallback={<Fallback />}>
+          <ArticleComponentTester invalidIfStale />
+        </Suspense>
+      </StateContext.Provider>
+    );
+    const { getByText } = render(tree);
+    expect(fbmock).not.toBeCalled();
+    const title = getByText(payload.title);
+    expect(title).toBeDefined();
+    expect(title.tagName).toBe('H3');
+  });
+  it('should suspend if result stale in cache and options.invalidIfStale is true', () => {
+    const { entities, result } = normalize(
+      payload,
+      InvalidIfStaleArticleResource.getEntitySchema(),
+    );
+    const fetchKey = InvalidIfStaleArticleResource.detailShape().getFetchKey(
+      payload,
+    );
+    const state = {
+      entities,
+      results: {
+        [fetchKey]: result,
+      },
+      meta: {
+        [fetchKey]: {
+          date: 0,
+          expiresAt: 0,
+        },
+      },
+    };
+
+    const tree = (
+      <StateContext.Provider value={state}>
+        <DispatchContext.Provider value={() => {}}>
+          <Suspense fallback={<Fallback />}>
+            <ArticleComponentTester invalidIfStale />
+          </Suspense>
+        </DispatchContext.Provider>
+      </StateContext.Provider>
+    );
+    render(tree);
+    expect(fbmock).toHaveBeenCalled();
+  });
+
+  // taken from integration
+  it('useResourceNew() should throw errors on bad network', async () => {
+    const { result, waitForNextUpdate } = renderRestHook(() => {
+      return useResourceNew(CoolerArticleResource.detailShape(), {
+        title: '0',
+      });
+    });
+    expect(result.current).toBe(null);
+    await waitForNextUpdate();
+    expect(result.error).toBeDefined();
+    expect((result.error as any).status).toBe(403);
+  });
+
+  it('useResourceNew() should throw errors on bad network (multiarg)', async () => {
+    const { result, waitForNextUpdate } = renderRestHook(() => {
+      return useResourceNew([
+        CoolerArticleResource.detailShape(),
+        {
+          title: '0',
+        },
+      ]);
+    });
+    expect(result.current).toBe(null);
+    await waitForNextUpdate();
+    expect(result.error).toBeDefined();
+    expect((result.error as any).status).toBe(403);
+  });
+
+  it('should resolve parallel useResourceNew() request', async () => {
+    const { result, waitForNextUpdate } = renderRestHook(() => {
+      return useResourceNew(
+        [
+          CoolerArticleResource.detailShape(),
+          {
+            id: payload.id,
+          },
+        ],
+        [UserResource.listShape(), {}],
+      );
+    });
+    expect(result.current).toBe(null);
+    await waitForNextUpdate();
+    const [article, users] = result.current;
+    expect(article instanceof CoolerArticleResource).toBe(true);
+    expect(article.title).toBe(payload.title);
+    expect(users).toBeDefined();
+    expect(users.length).toBeTruthy();
+    expect(users[0] instanceof UserResource).toBe(true);
+  });
+
+  it('should not suspend with no params to useResourceNew()', () => {
+    let article: any;
+    const { result } = renderRestHook(() => {
+      article = useResourceNew(CoolerArticleResource.detailShape(), null);
+      return 'done';
+    });
+    expect(result.current).toBe('done');
+    expect(article).toBeNull();
+  });
+});

