diff --git a/packages/core/src/react-integration/newhooks/__tests__/subscriptions.tsx b/packages/core/src/react-integration/newhooks/__tests__/subscriptions.tsx
new file mode 100644
index 0000000..2c9f0bb
--- /dev/null
+++ b/packages/core/src/react-integration/newhooks/__tests__/subscriptions.tsx
@@ -0,0 +1,266 @@
+import React from 'react';
+import { renderHook } from '@testing-library/react-hooks';
+import nock from 'nock';
+import { PollingArticleResource, ArticleResource } from '__tests__/new';
+import {
+  actionTypes,
+  Controller,
+  ControllerContext,
+  useCache,
+} from '@rest-hooks/core';
+
+import {
+  makeCacheProvider,
+  makeExternalCacheProvider,
+  makeRenderRestHook,
+} from '../../../../../test';
+import useSubscription from '../useSubscription';
+
+let mynock: nock.Scope;
+
+describe.each([
+  ['CacheProvider', makeCacheProvider],
+  ['ExternalCacheProvider', makeExternalCacheProvider],
+] as const)(`%s with subscriptions`, (_, makeProvider) => {
+  const articlePayload = {
+    id: 5,
+    title: 'hi ho',
+    content: 'whatever',
+    tags: ['a', 'best', 'react'],
+  };
+  let renderRestHook: ReturnType<typeof makeRenderRestHook>;
+
+  function onError(e: any) {
+    e.preventDefault();
+  }
+  beforeEach(() => {
+    if (typeof addEventListener === 'function')
+      addEventListener('error', onError);
+  });
+  afterEach(() => {
+    if (typeof removeEventListener === 'function')
+      removeEventListener('error', onError);
+  });
+
+  beforeAll(() => {
+    ArticleResource.detail().pollFrequency;
+    PollingArticleResource.detail().pollFrequency;
+  });
+
+  beforeEach(() => {
+    nock(/.*/)
+      .persist()
+      .defaultReplyHeaders({
+        'Access-Control-Allow-Origin': '*',
+        'Content-Type': 'application/json',
+      })
+      .options(/.*/)
+      .reply(200);
+    mynock = nock(/.*/).defaultReplyHeaders({
+      'Access-Control-Allow-Origin': '*',
+      'Content-Type': 'application/json',
+    });
+    mynock
+      .get(`/article-cooler/${articlePayload.id}`)
+      .reply(200, articlePayload)
+      .get(`/article/${articlePayload.id}`)
+      .reply(200, articlePayload);
+    renderRestHook = makeRenderRestHook(makeProvider);
+  });
+  afterEach(() => {
+    nock.cleanAll();
+  });
+
+  it('useSubscription() + useCache()', async () => {
+    jest.useFakeTimers();
+    const frequency = PollingArticleResource.detail().pollFrequency as number;
+    expect(frequency).toBeDefined();
+
+    const { result, waitForNextUpdate, rerender } = renderRestHook(
+      ({ active }) => {
+        useSubscription(
+          PollingArticleResource.detail(),
+          active ? articlePayload : null,
+        );
+        return useCache(PollingArticleResource.detail(), articlePayload);
+      },
+      { initialProps: { active: true } },
+    );
+
+    await validateSubscription(
+      result,
+      frequency,
+      waitForNextUpdate,
+      articlePayload,
+    );
+
+    // should not update if active is false
+    rerender({ active: false });
+    mynock
+      .get(`/article/${articlePayload.id}`)
+      .reply(200, { ...articlePayload, title: 'sixer' });
+    jest.advanceTimersByTime(frequency);
+    expect((result.current as any).title).toBe('fiver');
+
+    // errors should not fail when data already exists
+    nock.cleanAll();
+    mynock.get(`/article/${articlePayload.id}`).reply(403, () => {
+      return { message: 'you fail' };
+    });
+    rerender({ active: true });
+    jest.advanceTimersByTime(frequency);
+    expect((result.current as any).title).toBe('fiver');
+    jest.useRealTimers();
+  });
+
+  it('should console.error() with no frequency specified', async () => {
+    const oldError = console.error;
+    const spy = (console.error = jest.fn());
+
+    const { result, waitForNextUpdate } = renderRestHook(() => {
+      useSubscription(ArticleResource.detail(), articlePayload);
+    });
+    expect(result.error).toBeUndefined();
+    expect(spy.mock.calls[0]).toMatchSnapshot();
+
+    console.error = oldError;
+  });
+
+  it('useSubscription() without active arg', async () => {
+    jest.useFakeTimers();
+    const frequency = PollingArticleResource.detail().pollFrequency as number;
+    expect(frequency).toBeDefined();
+    expect(
+      PollingArticleResource.detail().options?.pollFrequency,
+    ).toBeDefined();
+    expect(
+      PollingArticleResource.anotherDetail().options?.pollFrequency,
+    ).toBeDefined();
+
+    const { result, waitForNextUpdate } = renderRestHook(() => {
+      useSubscription(PollingArticleResource.detail(), articlePayload);
+      return useCache(PollingArticleResource.detail(), articlePayload);
+    });
+
+    await validateSubscription(
+      result,
+      frequency,
+      waitForNextUpdate,
+      articlePayload,
+    );
+    jest.useRealTimers();
+  });
+
+  it('useSubscription() should dispatch rest-hooks/subscribe only once even with rerender', () => {
+    const fakeDispatch = jest.fn();
+    const controller = new Controller({ dispatch: fakeDispatch });
+
+    const { rerender } = renderHook(
+      () => {
+        useSubscription(PollingArticleResource.list(), { id: 5 });
+      },
+      {
+        wrapper: function Wrapper({ children }: any) {
+          return (
+            <ControllerContext.Provider value={controller}>
+              {children}
+            </ControllerContext.Provider>
+          );
+        },
+      },
+    );
+    expect(fakeDispatch.mock.calls.length).toBe(1);
+    for (let i = 0; i < 2; ++i) {
+      rerender();
+    }
+    expect(fakeDispatch.mock.calls.length).toBe(1);
+  });
+
+  it('useSubscription() should unsubscribe with null arguments', () => {
+    const fakeDispatch = jest.fn();
+    const controller = new Controller({ dispatch: fakeDispatch });
+
+    const { rerender } = renderHook(
+      ({ id }: { id: number | null }) => {
+        useSubscription(PollingArticleResource.list(), id ? { id } : null);
+      },
+      {
+        initialProps: { id: 5 } as { id: number | null },
+        wrapper: function Wrapper({ children }: any) {
+          return (
+            <ControllerContext.Provider value={controller}>
+              {children}
+            </ControllerContext.Provider>
+          );
+        },
+      },
+    );
+    expect(fakeDispatch.mock.calls.length).toBe(1);
+    for (let i = 0; i < 3; ++i) {
+      rerender({ id: null });
+    }
+    expect(fakeDispatch.mock.calls.length).toBe(2);
+    expect(fakeDispatch.mock.calls[0][0].type).toBe(actionTypes.SUBSCRIBE_TYPE);
+    expect(fakeDispatch.mock.calls[1][0].type).toBe(
+      actionTypes.UNSUBSCRIBE_TYPE,
+    );
+    expect(fakeDispatch.mock.calls[1][0].key).toBe(
+      fakeDispatch.mock.calls[0][0].key,
+    );
+  });
+});
+
+it('useSubscription() should include extra options in dispatched meta', () => {
+  const fakeDispatch = jest.fn();
+  const controller = new Controller({ dispatch: fakeDispatch });
+
+  renderHook(
+    () => {
+      useSubscription(PollingArticleResource.pusher(), {});
+    },
+    {
+      wrapper: function Wrapper({ children }: any) {
+        return (
+          <ControllerContext.Provider value={controller}>
+            {children}
+          </ControllerContext.Provider>
+        );
+      },
+    },
+  );
+
+  const spy = fakeDispatch.mock.calls[0][0];
+  expect(spy.meta.options.extra.eventType).toEqual(
+    'PollingArticleResource:fetch',
+  );
+});
+
+async function validateSubscription(
+  result: {
+    readonly current: PollingArticleResource | undefined;
+    readonly error?: Error;
+  },
+  frequency: number,
+  waitForNextUpdate: () => Promise<void>,
+  articlePayload: {
+    id: number;
+    title: string;
+    content: string;
+    tags: string[];
+  },
+) {
+  // should be null to start
+  expect(result.current).toBeUndefined();
+  // should be defined after frequency milliseconds
+  jest.advanceTimersByTime(frequency);
+  await waitForNextUpdate();
+  expect(result.current).toBeInstanceOf(PollingArticleResource);
+  expect(result.current).toEqual(PollingArticleResource.fromJS(articlePayload));
+  // should update again after frequency
+  mynock
+    .get(`/article/${articlePayload.id}`)
+    .reply(200, { ...articlePayload, title: 'fiver' });
+  jest.advanceTimersByTime(frequency);
+  await waitForNextUpdate();
+  expect((result.current as any).title).toBe('fiver');
+}

diff --git a/packages/core/src/react-integration/newhooks/__tests__/useCache.tsx b/packages/core/src/react-integration/newhooks/__tests__/useCache.tsx
new file mode 100644
index 0000000..f75520e
--- /dev/null
+++ b/packages/core/src/react-integration/newhooks/__tests__/useCache.tsx
@@ -0,0 +1,239 @@
+import {
+  CoolerArticleResource,
+  PaginatedArticleResource,
+  InvalidIfStaleArticleResource,
+  GetNoEntities,
+} from '__tests__/new';
+import React, { useEffect } from 'react';
+
+// relative imports to avoid circular dependency in tsconfig references
+import { makeRenderRestHook, makeCacheProvider } from '../../../../../test';
+import useCache from '../useCache';
+import { articlesPages, payload, nested } from '../test-fixtures';
+
+describe('useCache()', () => {
+  let renderRestHook: ReturnType<typeof makeRenderRestHook>;
+  beforeEach(() => {
+    renderRestHook = makeRenderRestHook(makeCacheProvider);
+  });
+
+  it('should be null with empty state', () => {
+    const { result } = renderRestHook(() => {
+      return useCache(CoolerArticleResource.detail(), payload);
+    }, {});
+    // @ts-expect-error
+    result.current?.doesnotexist;
+    expect(result.current).toBe(undefined);
+  });
+
+  it('should read with no params Endpoint', async () => {
+    const List = CoolerArticleResource.list().extend({
+      fetch() {
+        return CoolerArticleResource.list()({});
+      },
+    });
+    const { result } = renderRestHook(
+      () => {
+        return useCache(List);
+      },
+      { initialFixtures: [{ endpoint: List, args: [], response: nested }] },
+    );
+    expect(result.current?.length).toEqual(nested.length);
+
+    // @ts-expect-error
+    () => useCache(List, 5);
+    // @ts-expect-error
+    () => useCache(List, {});
+    // @ts-expect-error
+    () => useCache(List, '5');
+  });
+
+  it('should read with id params Endpoint', async () => {
+    const Detail = CoolerArticleResource.detail().extend({
+      fetch(id: number) {
+        return CoolerArticleResource.detail()({ id });
+      },
+    });
+    const { result } = renderRestHook(
+      () => {
+        return useCache(Detail, 5);
+      },
+      { initialFixtures: [{ endpoint: Detail, args: [5], response: payload }] },
+    );
+    expect(result.current).toEqual(CoolerArticleResource.fromJS(payload));
+
+    // @ts-expect-error
+    () => useCache(Detail);
+    // @ts-expect-error
+    () => useCache(Detail, 5, 10);
+    // @ts-expect-error
+    () => useCache(Detail, {});
+    // @ts-expect-error
+    () => useCache(Detail, '5');
+  });
+
+  it('should return undefined in entities slots when results are not found', async () => {
+    const userId = '5';
+    const { result } = renderRestHook(() => {
+      return useCache(GetNoEntities, { userId });
+    });
+    expect(result.current).toEqual({ firstThing: '', someItems: undefined });
+  });
+
+  it('should select singles', () => {
+    const results = [
+      {
+        request: CoolerArticleResource.detail(),
+        params: payload,
+        result: payload,
+      },
+    ];
+    const { result } = renderRestHook(
+      () => {
+        return useCache(CoolerArticleResource.detail(), payload);
+      },
+      { results },
+    );
+
+    expect(result.current).toBeTruthy();
+    expect(result.current?.title).toBe(payload.title);
+  });
+
+  it('should not select when results are stale and invalidIfStale is true', () => {
+    const realDate = global.Date.now;
+    Date.now = jest.fn(() => 999999999);
+    const results = [
+      {
+        request: InvalidIfStaleArticleResource.detail(),
+        params: payload,
+        result: payload,
+      },
+    ];
+    const { result, rerender } = renderRestHook(
+      props => {
+        return useCache(InvalidIfStaleArticleResource.detail(), props);
+      },
+      { results, initialProps: { id: payload.id } },
+    );
+
+    expect(result.current).toBeDefined();
+    Date.now = jest.fn(() => 999999999 * 3);
+
+    rerender({ id: payload.id * 2 });
+    expect(result.current).toBeUndefined();
+    rerender({ id: payload.id });
+    expect(result.current).toBeUndefined();
+
+    global.Date.now = realDate;
+  });
+
+  it('should select paginated results', () => {
+    const results = [
+      {
+        request: PaginatedArticleResource.list(),
+        params: {},
+        result: articlesPages,
+      },
+    ];
+    const { result } = renderRestHook(
+      () => {
+        return useCache(PaginatedArticleResource.list(), {});
+      },
+      { results },
+    );
+    expect(result.current).toBeDefined();
+    if (!result.current) return;
+    expect(result.current.results).toBeDefined();
+    if (!result.current.results) return;
+    expect(result.current.results.length).toBe(articlesPages.results.length);
+    expect(result.current.results[0]).toBeInstanceOf(PaginatedArticleResource);
+    expect(result.current.results).toMatchSnapshot();
+  });
+
+  it('should return identical value no matter how many re-renders', () => {
+    const results = [
+      {
+        request: PaginatedArticleResource.list(),
+        params: {},
+        result: articlesPages,
+      },
+    ];
+    const track = jest.fn();
+
+    const { rerender } = renderRestHook(
+      () => {
+        const articles = useCache(PaginatedArticleResource.list(), {});
+        useEffect(track, [articles]);
+      },
+      { results },
+    );
+
+    expect(track.mock.calls.length).toBe(1);
+    for (let i = 0; i < 2; ++i) {
+      rerender();
+    }
+    expect(track.mock.calls.length).toBe(1);
+  });
+
+  describe('Nested with defaults', () => {
+    it('should send defaults with nothing in state', () => {
+      const defaults = { prevPage: '', nextPage: '', results: undefined };
+      const { result } = renderRestHook(
+        () => {
+          return useCache(PaginatedArticleResource.list(), {});
+        },
+        { results: [] },
+      );
+      expect(result.current).toEqual(defaults);
+    });
+
+    it('should find results', () => {
+      const results = [
+        {
+          request: PaginatedArticleResource.list(),
+          params: {},
+          result: articlesPages,
+        },
+      ];
+      const { result } = renderRestHook(
+        () => {
+          return useCache(PaginatedArticleResource.list(), {});
+        },
+        { results },
+      );
+      expect(result.current).toBeTruthy();
+      expect(result.current.nextPage).toBe(articlesPages.nextPage);
+      expect(result.current.prevPage).toBe(articlesPages.prevPage);
+      expect(result.current.results).toEqual(
+        articlesPages.results.map(article =>
+          PaginatedArticleResource.fromJS(article),
+        ),
+      );
+    });
+
+    it('should return identical value no matter how many re-renders', () => {
+      const results = [
+        {
+          request: PaginatedArticleResource.list(),
+          params: {},
+          result: articlesPages,
+        },
+      ];
+      const track = jest.fn();
+
+      const { rerender } = renderRestHook(
+        () => {
+          useEffect(track, [results]);
+          return useCache(PaginatedArticleResource.list(), {});
+        },
+        { results },
+      );
+
+      expect(track.mock.calls.length).toBe(1);
+      for (let i = 0; i < 2; ++i) {
+        rerender();
+      }
+      expect(track.mock.calls.length).toBe(1);
+    });
+  });
+});

diff --git a/packages/core/src/react-integration/newhooks/__tests__/useFetch.web.tsx b/packages/core/src/react-integration/newhooks/__tests__/useFetch.web.tsx
new file mode 100644
index 0000000..d562b0e
--- /dev/null
+++ b/packages/core/src/react-integration/newhooks/__tests__/useFetch.web.tsx
@@ -0,0 +1,183 @@
+import { CoolerArticleResource, StaticArticleResource } from '__tests__/new';
+import React, { Suspense } from 'react';
+import { render } from '@testing-library/react';
+import { renderHook } from '@testing-library/react-hooks';
+import nock from 'nock';
+
+// relative imports to avoid circular dependency in tsconfig references
+import {
+  StateContext,
+  initialState,
+  State,
+  ActionTypes,
+  ControllerContext,
+  Controller,
+} from '@rest-hooks/core';
+
+import { makeRenderRestHook, makeCacheProvider } from '../../../../../test';
+import useFetch from '../useFetch';
+import { users, payload } from '../test-fixtures';
+
+async function testDispatchFetch(
+  Component: React.FunctionComponent<any>,
+  payloads: any[],
+) {
+  const dispatch = jest.fn();
+  const controller = new Controller({ dispatch });
+
+  const tree = (
+    <ControllerContext.Provider value={controller}>
+      <Suspense fallback={null}>
+        <Component />
+      </Suspense>
+    </ControllerContext.Provider>
+  );
+  render(tree);
+  expect(dispatch).toHaveBeenCalled();
+  expect(dispatch.mock.calls.length).toBe(payloads.length);
+  let i = 0;
+  for (const call of dispatch.mock.calls) {
+    delete call[0]?.meta?.createdAt;
+    expect(call[0]).toMatchSnapshot();
+    const action = call[0];
+    const res = await action.payload();
+    expect(res).toEqual(payloads[i]);
+    i++;
+  }
+}
+
+function testRestHook(
+  callback: () => void,
+  state: State<unknown>,
+  dispatch = (v: ActionTypes) => Promise.resolve(),
+) {
+  const controller = new Controller({ dispatch });
+
+  return renderHook(callback, {
+    wrapper: function Wrapper({ children }) {
+      return (
+        <ControllerContext.Provider value={controller}>
+          <StateContext.Provider value={state}>
+            {children}
+          </StateContext.Provider>
+        </ControllerContext.Provider>
+      );
+    },
+  });
+}
+
+let mynock: nock.Scope;
+
+beforeAll(() => {
+  nock(/.*/)
+    .persist()
+    .defaultReplyHeaders({
+      'Access-Control-Allow-Origin': '*',
+      'Content-Type': 'application/json',
+    })
+    .options(/.*/)
+    .reply(200);
+  mynock = nock(/.*/).defaultReplyHeaders({
+    'Access-Control-Allow-Origin': '*',
+    'Content-Type': 'application/json',
+  });
+});
+
+afterAll(() => {
+  nock.cleanAll();
+});
+
+describe('useFetch', () => {
+  let renderRestHook: ReturnType<typeof makeRenderRestHook>;
+  beforeEach(() => {
+    mynock.get(`/article-cooler/${payload.id}`).reply(200, payload);
+    mynock.get(`/article-static/${payload.id}`).reply(200, payload);
+    mynock.get(`/user/`).reply(200, users);
+    renderRestHook = makeRenderRestHook(makeCacheProvider);
+  });
+  afterEach(() => {
+    nock.cleanAll();
+  });
+
+  it('should dispatch singles', async () => {
+    function FetchTester() {
+      useFetch(CoolerArticleResource.detail(), payload);
+      return null;
+    }
+    await testDispatchFetch(FetchTester, [payload]);
+  });
+
+  it('should not dispatch will null params', () => {
+    const dispatch = jest.fn();
+    let params: any = null;
+    const { rerender } = testRestHook(
+      () => {
+        useFetch(CoolerArticleResource.detail(), params);
+      },
+      initialState,
+      dispatch,
+    );
+    expect(dispatch).toBeCalledTimes(0);
+    params = payload;
+    rerender();
+    expect(dispatch).toBeCalled();
+  });
+
+  it('should dispatch with resource defined dataExpiryLength', async () => {
+    function FetchTester() {
+      useFetch(StaticArticleResource.detail(), payload);
+      return null;
+    }
+    await testDispatchFetch(FetchTester, [payload]);
+  });
+
+  it('should dispatch with fetch shape defined dataExpiryLength', async () => {
+    function FetchTester() {
+      useFetch(StaticArticleResource.longLiving(), payload);
+      return null;
+    }
+    await testDispatchFetch(FetchTester, [payload]);
+  });
+
+  it('should dispatch with fetch shape defined errorExpiryLength', async () => {
+    function FetchTester() {
+      useFetch(StaticArticleResource.neverRetryOnError(), payload);
+      return null;
+    }
+    await testDispatchFetch(FetchTester, [payload]);
+  });
+
+  it('should not refetch after expiry and render', async () => {
+    let time = 1000;
+    global.Date.now = jest.fn(() => time);
+    nock.cleanAll();
+    const fetchMock = jest.fn(() => payload);
+    mynock.get(`/article-cooler/${payload.id}`).reply(200, fetchMock).persist();
+    const results: any[] = [
+      {
+        request: CoolerArticleResource.detail(),
+        params: payload,
+        result: payload,
+      },
+    ];
+    const { result, rerender } = renderRestHook(
+      () => {
+        return useFetch(CoolerArticleResource.detail(), payload);
+      },
+      { results },
+    );
+    await result.current;
+    expect(fetchMock).toHaveBeenCalledTimes(0);
+    time += 100;
+    rerender();
+    await result.current;
+    expect(fetchMock).toHaveBeenCalledTimes(0);
+    // eslint-disable-next-line require-atomic-updates
+    time += 610000000;
+    rerender();
+    await result.current;
+    rerender();
+    await result.current;
+    expect(fetchMock).toHaveBeenCalledTimes(0);
+  });
+});

diff --git a/packages/core/src/react-integration/newhooks/__tests__/useSuspense.web.tsx b/packages/core/src/react-integration/newhooks/__tests__/useSuspense.web.tsx
new file mode 100644
index 0000000..036b7c7
--- /dev/null
+++ b/packages/core/src/react-integration/newhooks/__tests__/useSuspense.web.tsx
@@ -0,0 +1,565 @@
+import {
+  CoolerArticleResource,
+  InvalidIfStaleArticleResource,
+  GetPhoto,
+  GetPhotoUndefined,
+  GetNoEntities,
+  ArticleTimedResource,
+  ContextAuthdArticle,
+  AuthContext,
+} from '__tests__/new';
+import { createEntityMeta } from '__tests__/utils';
+import {
+  State,
+  useController,
+  ControllerContext,
+  StateContext,
+  initialState,
+  Controller,
+} from '@rest-hooks/core';
+import React, { Suspense } from 'react';
+import { render } from '@testing-library/react';
+import nock from 'nock';
+
+// relative imports to avoid circular dependency in tsconfig references
+
+import { normalize } from '@rest-hooks/normalizr';
+import { Endpoint, ReadEndpoint } from '@rest-hooks/endpoint';
+import { act } from '@testing-library/react-hooks';
+
+import {
+  makeRenderRestHook,
+  makeCacheProvider,
+  mockInitialState,
+} from '../../../../../test';
+import useSuspense from '../useSuspense';
+import { payload, users, nested } from '../test-fixtures';
+
+async function testDispatchFetch(
+  Component: React.FunctionComponent<any>,
+  payloads: any[],
+) {
+  const dispatch = jest.fn();
+  const controller = new Controller({ dispatch });
+
+  const tree = (
+    <ControllerContext.Provider value={controller}>
+      <Suspense fallback={null}>
+        <Component />
+      </Suspense>
+    </ControllerContext.Provider>
+  );
+  render(tree);
+  expect(dispatch).toHaveBeenCalled();
+  expect(dispatch.mock.calls.length).toBe(payloads.length);
+  let i = 0;
+  for (const call of dispatch.mock.calls) {
+    delete call[0]?.meta?.createdAt;
+    expect(call[0]).toMatchSnapshot();
+    const action = call[0];
+    const res = await action.payload();
+    expect(res).toEqual(payloads[i]);
+    i++;
+  }
+}
+
+function ArticleComponentTester({ invalidIfStale = false }) {
+  const resource = invalidIfStale
+    ? InvalidIfStaleArticleResource
+    : CoolerArticleResource;
+  const article = useSuspense(resource.detail(), {
+    id: payload.id,
+  });
+  return (
+    <div>
+      <h3>{article.title}</h3>
+      <p>{article.content}</p>
+    </div>
+  );
+}
+
+describe('useSuspense()', () => {
+  let renderRestHook: ReturnType<typeof makeRenderRestHook>;
+  const fbmock = jest.fn();
+
+  async function testMalformedResponse(
+    payload: any,
+    endpoint: ReadEndpoint = CoolerArticleResource.detail(),
+  ) {
+    nock(/.*/)
+      .persist()
+      .defaultReplyHeaders({
+        'Access-Control-Allow-Origin': '*',
+        'Access-Control-Allow-Headers': '*',
+        'Content-Type': 'application/json',
+      })
+      .get(`/article-cooler/400`)
+      .reply(200, payload);
+
+    const { result, waitForNextUpdate } = renderRestHook(() => {
+      return useSuspense(endpoint as any, {
+        id: 400,
+      });
+    });
+    expect(result.current).toBeUndefined();
+    await waitForNextUpdate();
+    expect(result.error).toBeDefined();
+    expect((result.error as any).status).toBeGreaterThan(399);
+    expect(result.error).toMatchSnapshot();
+  }
+
+  function Fallback() {
+    fbmock();
+    return null;
+  }
+
+  beforeAll(() => {
+    nock(/.*/)
+      .persist()
+      .defaultReplyHeaders({
+        'Access-Control-Allow-Origin': '*',
+        'Access-Control-Allow-Headers': 'Access-Token',
+        'Content-Type': 'application/json',
+      })
+      .options(/.*/)
+      .reply(200)
+      .get(`/article-cooler/${payload.id}`)
+      .reply(200, payload)
+      .get(`/article-time/${payload.id}`)
+      .reply(200, { ...payload, createdAt: '2020-06-07T02:00:15+0000' })
+      .delete(`/article-cooler/${payload.id}`)
+      .reply(204, '')
+      .delete(`/article/${payload.id}`)
+      .reply(200, {})
+      .get(`/article-cooler/0`)
+      .reply(403, {})
+      .get(`/article-cooler/666`)
+      .reply(200, '')
+      .get(`/article-cooler/`)
+      .reply(200, nested)
+      .get(`/user/`)
+      .reply(200, users);
+  });
+
+  afterAll(() => {
+    nock.cleanAll();
+  });
+
+  beforeEach(() => {
+    renderRestHook = makeRenderRestHook(makeCacheProvider);
+  });
+
+  it('should dispatch an action that fetches', async () => {
+    await testDispatchFetch(ArticleComponentTester, [payload]);
+  });
+
+  it('should NOT suspend if result already in cache and options.invalidIfStale is false', () => {
+    const state: State<unknown> = mockInitialState([
+      {
+        request: CoolerArticleResource.detail(),
+        params: payload,
+        result: payload,
+      },
+    ]) as any;
+
+    const tree = (
+      <StateContext.Provider value={state}>
+        <Suspense fallback={<Fallback />}>
+          <ArticleComponentTester />
+        </Suspense>
+      </StateContext.Provider>
+    );
+    const { getByText } = render(tree);
+    expect(fbmock).not.toBeCalled();
+    const title = getByText(payload.title);
+    expect(title).toBeDefined();
+    expect(title.tagName).toBe('H3');
+  });
+  it('should NOT suspend even when result is stale and options.invalidIfStale is false', () => {
+    const { entities, result } = normalize(payload, CoolerArticleResource);
+    const fetchKey = CoolerArticleResource.detail().key(payload);
+    const state = {
+      ...initialState,
+      entities,
+      entityMeta: createEntityMeta(entities),
+      results: {
+        [fetchKey]: result,
+      },
+      meta: {
+        [fetchKey]: {
+          date: 0,
+          expiresAt: 0,
+        },
+      },
+    };
+    const controller = new Controller({ dispatch: () => Promise.resolve() });
+    const tree = (
+      <StateContext.Provider value={state}>
+        <ControllerContext.Provider value={controller}>
+          <Suspense fallback={<Fallback />}>
+            <ArticleComponentTester />
+          </Suspense>{' '}
+        </ControllerContext.Provider>
+      </StateContext.Provider>
+    );
+    const { getByText } = render(tree);
+    expect(fbmock).not.toBeCalled();
+    const title = getByText(payload.title);
+    expect(title).toBeDefined();
+    expect(title.tagName).toBe('H3');
+  });
+  it('should NOT suspend if result is not stale and options.invalidIfStale is true', () => {
+    const { entities, result } = normalize(
+      payload,
+      InvalidIfStaleArticleResource,
+    );
+    const fetchKey = InvalidIfStaleArticleResource.detail().key(payload);
+    const state = {
+      ...initialState,
+      entities,
+      results: {
+        [fetchKey]: result,
+      },
+      entityMeta: createEntityMeta(entities),
+      meta: {
+        [fetchKey]: {
+          date: Infinity,
+          expiresAt: Infinity,
+        },
+      },
+    };
+
+    const tree = (
+      <StateContext.Provider value={state}>
+        <Suspense fallback={<Fallback />}>
+          <ArticleComponentTester invalidIfStale />
+        </Suspense>
+      </StateContext.Provider>
+    );
+    const { getByText } = render(tree);
+    expect(fbmock).not.toBeCalled();
+    const title = getByText(payload.title);
+    expect(title).toBeDefined();
+    expect(title.tagName).toBe('H3');
+  });
+  it('should suspend if result stale in cache and options.invalidIfStale is true', () => {
+    const { entities, result } = normalize(
+      payload,
+      InvalidIfStaleArticleResource,
+    );
+    const fetchKey =
+      InvalidIfStaleArticleResource.detail().getFetchKey(payload);
+    const state = {
+      ...initialState,
+      entities,
+      results: {
+        [fetchKey]: result,
+      },
+      entityMeta: createEntityMeta(entities),
+      meta: {
+        [fetchKey]: {
+          date: 0,
+          expiresAt: 0,
+        },
+      },
+    };
+    const controller = new Controller({ dispatch: () => Promise.resolve() });
+
+    const tree = (
+      <StateContext.Provider value={state}>
+        <ControllerContext.Provider value={controller}>
+          <Suspense fallback={<Fallback />}>
+            <ArticleComponentTester invalidIfStale />
+          </Suspense>
+        </ControllerContext.Provider>
+      </StateContext.Provider>
+    );
+    render(tree);
+    expect(fbmock).toHaveBeenCalled();
+  });
+
+  describe('errors', () => {
+    let errorspy: jest.SpyInstance;
+    beforeEach(() => {
+      errorspy = jest
+        .spyOn(global.console, 'error')
+        .mockImplementation(() => {});
+    });
+    afterEach(() => {
+      errorspy.mockRestore();
+    });
+
+    // taken from integration
+    it('should throw errors on bad network', async () => {
+      const { result, waitForNextUpdate } = renderRestHook(() => {
+        return useSuspense(CoolerArticleResource.detail(), {
+          id: '0',
+        });
+      });
+      expect(result.current).toBeUndefined();
+      await waitForNextUpdate();
+      expect(result.error).toBeDefined();
+      expect((result.error as any).status).toBe(403);
+    });
+
+    it('should throw error when response is array when expecting entity', async () => {
+      await testMalformedResponse([]);
+    });
+
+    it('should throw error when response is {} when expecting entity', async () => {
+      await testMalformedResponse({});
+    });
+
+    it('should throw error when response is number when expecting entity', async () => {
+      await testMalformedResponse(5);
+    });
+
+    it('should throw error when response is string when expecting entity', async () => {
+      await testMalformedResponse('hi');
+    });
+
+    /* TODO: Add these back when we have opt-in required
+  it('should throw error when response is string when expecting nested entity', async () => {
+    const endpoint = CoolerArticleResource.detail().extend({
+      schema: { data: CoolerArticleResource },
+    });
+    await testMalformedResponse('hi', endpoint);
+  });
+
+  it('should throw error when response is nested string when expecting nested entity', async () => {
+    const endpoint = CoolerArticleResource.detail().extend({
+      schema: { data: CoolerArticleResource },
+    });
+    await testMalformedResponse({ data: 5, parcel: 2 }, endpoint);
+  });
+
+  it('should throw error when response is nested missing id when expecting nested entity', async () => {
+    const endpoint = CoolerArticleResource.detail().extend({
+      schema: { data: CoolerArticleResource },
+    });
+    await testMalformedResponse(
+      { data: { ...payload, id: undefined }, parcel: 2 },
+      endpoint,
+    );
+  });
+
+  it('should throw error when response is expected Resource inside Record', async () => {
+    class Scheme extends SimpleRecord {
+      data: CoolerArticleResource = CoolerArticleResource.fromJS();
+      optional: UserResource | null = null;
+      static schema = {
+        data: CoolerArticleResource,
+        optional: UserResource,
+      };
+    }
+    const endpoint = CoolerArticleResource.detail().extend({
+      schema: Scheme,
+    });
+    await testMalformedResponse({ data: null }, endpoint);
+  });*/
+  });
+
+  it('should not suspend with null params to useSuspense()', () => {
+    let article: any;
+    const { result } = renderRestHook(() => {
+      article = useSuspense(CoolerArticleResource.detail(), null);
+      return 'done';
+    });
+    expect(result.current).toBe('done');
+    expect(article).toBeUndefined();
+  });
+
+  it('should suspend with no params to useSuspense()', async () => {
+    const List = CoolerArticleResource.list().extend({
+      fetch() {
+        return CoolerArticleResource.list().fetch({});
+      },
+    });
+    const { result, waitForNextUpdate } = renderRestHook(() => {
+      return useSuspense(List);
+    });
+    expect(result.current).toBeUndefined();
+    await waitForNextUpdate();
+    expect(result.current.length).toEqual(nested.length);
+
+    // @ts-expect-error
+    () => useSuspense(List, 5);
+    // @ts-expect-error
+    () => useSuspense(List, {});
+    // @ts-expect-error
+    () => useSuspense(List, '5');
+  });
+
+  it('should read with id params Endpoint', async () => {
+    const Detail = CoolerArticleResource.detail().extend({
+      fetch(id: number) {
+        return CoolerArticleResource.detail()({ id });
+      },
+    });
+    const { result, waitForNextUpdate } = renderRestHook(() => {
+      return useSuspense(Detail, 5);
+    });
+    expect(result.current).toBeUndefined();
+    await waitForNextUpdate();
+    expect(result.current).toEqual(CoolerArticleResource.fromJS(payload));
+
+    // @ts-expect-error
+    () => useSuspense(Detail);
+    // @ts-expect-error
+    () => useSuspense(Detail, 5, 10);
+    // @ts-expect-error
+    () => useSuspense(Detail, {});
+    // @ts-expect-error
+    () => useSuspense(Detail, '5');
+  });
+
+  it('should work with shapes with no entities', async () => {
+    const userId = '5';
+    const response = { firstThing: '', someItems: [{ a: 5 }] };
+    nock(/.*/)
+      .defaultReplyHeaders({ 'access-control-allow-origin': '*' })
+      .get(`/users/${userId}/simple`)
+      .reply(200, response);
+    const { result, waitForNextUpdate } = renderRestHook(() => {
+      return useSuspense(GetNoEntities, { userId });
+    });
+    // undefined means it threw
+    expect(result.current).toBeUndefined();
+    await waitForNextUpdate();
+    expect(result.current).toStrictEqual(response);
+  });
+
+  it('should work with ArrayBuffer shapes', async () => {
+    const userId = '5';
+    const response = new ArrayBuffer(10);
+    nock(/.*/)
+      .defaultReplyHeaders({ 'access-control-allow-origin': '*' })
+      .get(`/users/${userId}/photo`)
+      .reply(200, response);
+    const { result, waitForNextUpdate } = renderRestHook(() => {
+      return useSuspense(GetPhoto, { userId });
+    });
+    // undefined means it threw
+    expect(result.current).toBeUndefined();
+    await waitForNextUpdate();
+    expect(result.current).toEqual(response);
+  });
+
+  it('should work with ArrayBuffer endpoint with undefined schema', async () => {
+    const userId = '5';
+    const response = new ArrayBuffer(99);
+    nock(/.*/)
+      .defaultReplyHeaders({
+        'access-control-allow-origin': '*',
+      })
+      .get(`/users/${userId}/photo2`)
+      .reply(200, response);
+    const { result, waitForNextUpdate } = renderRestHook(() => {
+      return useSuspense(GetPhotoUndefined, { userId });
+    });
+    // undefined means it threw
+    expect(result.current).toBeUndefined();
+    await waitForNextUpdate();
+    expect(result.current).toEqual(response);
+  });
+
+  it('should work with Serializable shapes', async () => {
+    const { result, waitForNextUpdate } = renderRestHook(() => {
+      return useSuspense(ArticleTimedResource.detail(), payload);
+    });
+    // undefined means it threw
+    expect(result.current).toBeUndefined();
+    await waitForNextUpdate();
+    expect(result.current.createdAt.getDate()).toBe(
+      result.current.createdAt.getDate(),
+    );
+    expect(result.current.createdAt).toEqual(
+      new Date('2020-06-07T02:00:15+0000'),
+    );
+    expect(result.current.id).toEqual(payload.id);
+    expect(result.current).toBeInstanceOf(ArticleTimedResource);
+  });
+
+  it('reset promises do not propagate', async () => {
+    let rejectIt: (reason?: any) => void = () => {};
+    const func = () => {
+      return new Promise((resolve, reject) => {
+        rejectIt = reject;
+      });
+    };
+    const MyEndpoint = new Endpoint(func, {
+      key() {
+        return 'MyEndpoint';
+      },
+    });
+    const { result, unmount } = renderRestHook(() => {
+      return useSuspense(MyEndpoint);
+    });
+    expect(result.current).toBeUndefined();
+    unmount();
+    act(() => rejectIt('failed'));
+    // the test will fail if promise is not caught
+  });
+
+  describe('context authentication', () => {
+    beforeAll(() => {
+      const mynock = nock(/.*/)
+        .persist()
+        .defaultReplyHeaders({
+          'Access-Control-Allow-Origin': '*',
+          'Access-Control-Allow-Headers': 'Access-Token',
+          'Content-Type': 'application/json',
+        })
+        .options(/.*/)
+        .reply(200);
+
+      mynock
+        .get(`/article/${payload.id}`)
+        .matchHeader('access-token', '')
+        .reply(200, { ...payload, title: 'unauthorized' })
+        .get(`/article/${payload.id}`)
+        .matchHeader('access-token', 'thepassword')
+        .reply(200, payload);
+    });
+
+    it('should use latest context when making requests', async () => {
+      const consoleSpy = jest.spyOn(console, 'error');
+      const wrapper = ({
+        children,
+        authToken,
+      }: React.PropsWithChildren<{
+        authToken: string;
+      }>) => (
+        <AuthContext.Provider value={authToken}>
+          {children}
+        </AuthContext.Provider>
+      );
+      const { result, waitForNextUpdate, rerender } = renderRestHook(
+        () => {
+          return {
+            data: useSuspense(ContextAuthdArticle.detail(), payload),
+            controller: useController(),
+            endpoint: ContextAuthdArticle.detail(),
+          };
+        },
+        {
+          wrapper,
+          initialProps: { authToken: '' },
+        },
+      );
+      // undefined means it threw (suspended)
+      expect(result.current).toBeUndefined();
+      await waitForNextUpdate();
+      expect(result.current.data.title).toBe('unauthorized');
+      rerender({ authToken: 'thepassword' });
+      const data = await result.current.controller.fetch(
+        result.current.endpoint,
+        payload,
+      );
+      expect(data).toEqual(payload);
+      expect(result.current.data.title).toEqual(payload.title);
+      // ensure we don't violate call-order changes
+      expect(consoleSpy.mock.calls.length).toBeLessThan(1);
+    });
+  });
+});

