@@ -0,0 +1,371 @@
+import React, { Suspense } from 'react';
+import { render } from '@testing-library/react';
+import nock from 'nock';
+import { normalize } from '../../resource';
+
+import { DispatchContext, StateContext } from '../context';
+import {
+  CoolerArticleResource,
+  UserResource,
+  InvalidIfStaleArticleResource,
+} from '../../__tests__/common';
+import { useResource } from '../hooks';
+import {
+  makeRenderRestHook,
+  makeCacheProvider,
+  mockInitialState,
+} from '../../../../test/src';
+import { payload, users, nested } from './fixtures';
+
+async function testDispatchFetch(
+  Component: React.FunctionComponent<any>,
+  payloads: any[],
+) {
+  const dispatch = jest.fn();
+  const tree = (
+    <DispatchContext.Provider value={dispatch}>
+      <Suspense fallback={null}>
+        <Component />
+      </Suspense>
+    </DispatchContext.Provider>
+  );
+  render(tree);
+  expect(dispatch).toHaveBeenCalled();
+  expect(dispatch.mock.calls.length).toBe(payloads.length);
+  let i = 0;
+  for (const call of dispatch.mock.calls) {
+    expect(call[0]).toMatchSnapshot();
+    const action = call[0];
+    const res = await action.payload();
+    expect(res).toEqual(payloads[i]);
+    i++;
+  }
+}
+
+function ArticleComponentTester({ invalidIfStale = false }) {
+  const resource = invalidIfStale
+    ? InvalidIfStaleArticleResource
+    : CoolerArticleResource;
+  const article = useResource(resource.detailShape(), {
+    id: payload.id,
+  });
+  return (
+    <div>
+      <h3>{article.title}</h3>
+      <p>{article.content}</p>
+    </div>
+  );
+}
+
+describe('useResource()', () => {
+  let renderRestHook: ReturnType<typeof makeRenderRestHook>;
+  const fbmock = jest.fn();
+
+  function Fallback() {
+    fbmock();
+    return null;
+  }
+
+  beforeEach(() => {
+    renderRestHook = makeRenderRestHook(makeCacheProvider);
+    nock('http://test.com')
+      .get(`/article-cooler/${payload.id}`)
+      .reply(200, payload);
+    nock('http://test.com')
+      .delete(`/article-cooler/${payload.id}`)
+      .reply(204, '');
+    nock('http://test.com')
+      .delete(`/article/${payload.id}`)
+      .reply(200, {});
+    nock('http://test.com')
+      .get(`/article-cooler/0`)
+      .reply(403, {});
+    nock('http://test.com')
+      .get(`/article-cooler/666`)
+      .reply(200, '');
+    nock('http://test.com')
+      .get(`/article-cooler/`)
+      .reply(200, nested);
+    nock('http://test.com')
+      .get(`/user/`)
+      .reply(200, users);
+  });
+  afterEach(() => {
+    nock.cleanAll();
+    renderRestHook.cleanup();
+  });
+
+  it('should dispatch an action that fetches', async () => {
+    await testDispatchFetch(ArticleComponentTester, [payload]);
+  });
+
+  it('should dispatch fetch when sent multiple arguments', async () => {
+    function MultiResourceTester() {
+      const [article, user] = useResource(
+        [
+          CoolerArticleResource.detailShape(),
+          {
+            id: payload.id,
+          },
+        ],
+        [UserResource.listShape(), {}],
+      );
+      return null;
+    }
+    await testDispatchFetch(MultiResourceTester, [payload, users]);
+  });
+  it('should throw same promise until both resolve', async () => {
+    const renderRestHook = makeRenderRestHook(makeCacheProvider);
+    jest.useFakeTimers();
+    nock('http://test.com')
+      .get(`/article-cooler/${payload.id}`)
+      .delay(1000)
+      .reply(200, payload);
+    nock('http://test.com')
+      .get(`/user/`)
+      .delay(2000)
+      .reply(200, users);
+
+    function MultiResourceTester() {
+      try {
+        const [article, user] = useResource(
+          [
+            CoolerArticleResource.detailShape(),
+            {
+              id: payload.id,
+            },
+          ],
+          [UserResource.listShape(), {}],
+        );
+        return article;
+      } catch (e) {
+        // TODO: we're not handling suspense properly so react complains
+        // When upgrading test util we should be able to fix this as we'll suspense ourselves.
+        if (typeof e.then === 'function') {
+          return e;
+        } else {
+          throw e;
+        }
+      }
+    }
+    const { rerender, result } = renderRestHook(MultiResourceTester);
+    const firstPromise = result.current;
+    expect(firstPromise).toBeDefined();
+    expect(typeof firstPromise.then).toBe('function');
+
+    jest.advanceTimersByTime(50);
+    rerender();
+    expect(result.current).toBe(firstPromise);
+    jest.advanceTimersByTime(1000);
+    rerender();
+    expect(result.current).toBe(firstPromise);
+    jest.advanceTimersByTime(2000);
+    rerender();
+    expect(result.current).toBe(firstPromise);
+
+    // TODO: we're not handling suspense properly so react complains
+    // When upgrading test util we should be able to fix this as we'll suspense ourselves.
+    const oldError = console.error;
+    console.error = () => {};
+    jest.runAllTimers();
+    await result.current;
+    rerender();
+    expect(result.current).toMatchInlineSnapshot(`
+      CoolerArticleResource {
+        "author": null,
+        "content": "whatever",
+        "id": 5,
+        "tags": Array [
+          "a",
+          "best",
+          "react",
+        ],
+        "title": "hi ho",
+      }
+    `);
+    // eslint-disable-next-line require-atomic-updates
+    console.error = oldError;
+  });
+  it('should NOT suspend if result already in cache and options.invalidIfStale is false', () => {
+    const state = mockInitialState([
+      {
+        request: CoolerArticleResource.detailShape(),
+        params: payload,
+        result: payload,
+      },
+    ]);
+
+    const tree = (
+      <StateContext.Provider value={state}>
+        <Suspense fallback={<Fallback />}>
+          <ArticleComponentTester />
+        </Suspense>
+      </StateContext.Provider>
+    );
+    const { getByText } = render(tree);
+    expect(fbmock).not.toBeCalled();
+    const title = getByText(payload.title);
+    expect(title).toBeDefined();
+    expect(title.tagName).toBe('H3');
+  });
+  it('should NOT suspend even when result is stale and options.invalidIfStale is false', () => {
+    const { entities, result } = normalize(
+      payload,
+      CoolerArticleResource.getEntitySchema(),
+    );
+    const fetchKey = CoolerArticleResource.detailShape().getFetchKey(payload);
+    const state = {
+      entities,
+      results: {
+        [fetchKey]: result,
+      },
+      meta: {
+        [fetchKey]: {
+          date: 0,
+          expiresAt: 0,
+        },
+      },
+    };
+
+    const tree = (
+      <StateContext.Provider value={state}>
+        <DispatchContext.Provider value={() => Promise.resolve()}>
+          <Suspense fallback={<Fallback />}>
+            <ArticleComponentTester />
+          </Suspense>{' '}
+        </DispatchContext.Provider>
+      </StateContext.Provider>
+    );
+    const { getByText } = render(tree);
+    expect(fbmock).not.toBeCalled();
+    const title = getByText(payload.title);
+    expect(title).toBeDefined();
+    expect(title.tagName).toBe('H3');
+  });
+  it('should NOT suspend if result is not stale and options.invalidIfStale is true', () => {
+    const { entities, result } = normalize(
+      payload,
+      InvalidIfStaleArticleResource.getEntitySchema(),
+    );
+    const fetchKey = InvalidIfStaleArticleResource.detailShape().getFetchKey(
+      payload,
+    );
+    const state = {
+      entities,
+      results: {
+        [fetchKey]: result,
+      },
+      meta: {
+        [fetchKey]: {
+          date: Infinity,
+          expiresAt: Infinity,
+        },
+      },
+    };
+
+    const tree = (
+      <StateContext.Provider value={state}>
+        <Suspense fallback={<Fallback />}>
+          <ArticleComponentTester invalidIfStale />
+        </Suspense>
+      </StateContext.Provider>
+    );
+    const { getByText } = render(tree);
+    expect(fbmock).not.toBeCalled();
+    const title = getByText(payload.title);
+    expect(title).toBeDefined();
+    expect(title.tagName).toBe('H3');
+  });
+  it('should suspend if result stale in cache and options.invalidIfStale is true', () => {
+    const { entities, result } = normalize(
+      payload,
+      InvalidIfStaleArticleResource.getEntitySchema(),
+    );
+    const fetchKey = InvalidIfStaleArticleResource.detailShape().getFetchKey(
+      payload,
+    );
+    const state = {
+      entities,
+      results: {
+        [fetchKey]: result,
+      },
+      meta: {
+        [fetchKey]: {
+          date: 0,
+          expiresAt: 0,
+        },
+      },
+    };
+
+    const tree = (
+      <StateContext.Provider value={state}>
+        <DispatchContext.Provider value={() => Promise.resolve()}>
+          <Suspense fallback={<Fallback />}>
+            <ArticleComponentTester invalidIfStale />
+          </Suspense>
+        </DispatchContext.Provider>
+      </StateContext.Provider>
+    );
+    render(tree);
+    expect(fbmock).toHaveBeenCalled();
+  });
+
+  // taken from integration
+  it('useResource() should throw errors on bad network', async () => {
+    const { result, waitForNextUpdate } = renderRestHook(() => {
+      return useResource(CoolerArticleResource.detailShape(), {
+        title: '0',
+      });
+    });
+    expect(result.current).toBe(null);
+    await waitForNextUpdate();
+    expect(result.error).toBeDefined();
+    expect((result.error as any).status).toBe(403);
+  });
+
+  it('useResource() should throw errors on bad network (multiarg)', async () => {
+    const { result, waitForNextUpdate } = renderRestHook(() => {
+      return useResource([
+        CoolerArticleResource.detailShape(),
+        {
+          title: '0',
+        },
+      ]);
+    });
+    expect(result.current).toBe(null);
+    await waitForNextUpdate();
+    expect(result.error).toBeDefined();
+    expect((result.error as any).status).toBe(403);
+  });
+
+  it('should resolve parallel useResource() request', async () => {
+    const { result, waitForNextUpdate } = renderRestHook(() => {
+      return useResource(
+        [
+          CoolerArticleResource.detailShape(),
+          {
+            id: payload.id,
+          },
+        ],
+        [UserResource.listShape(), {}],
+      );
+    });
+    await waitForNextUpdate();
+    const [article, users] = result.current;
+    expect(article instanceof CoolerArticleResource).toBe(true);
+    expect(article.title).toBe(payload.title);
+    expect(users).toBeDefined();
+    expect(users.length).toBeTruthy();
+    expect(users[0] instanceof UserResource).toBe(true);
+  });
+
+  it('should not suspend with no params to useResource()', () => {
+    let article: any;
+    const { result } = renderRestHook(() => {
+      article = useResource(CoolerArticleResource.detailShape(), null);
+      return 'done';
+    });
+    expect(result.current).toBe('done');
+    expect(article).toBeUndefined();
+  });
+});

diff --git a/packages/rest-hooks/src/react-integration/provider/__tests__/middleware.tsx b/packages/rest-hooks/src/react-integration/provider/__tests__/middleware.tsx
new file mode 100644
index 0000000..d672501
--- /dev/null
+++ b/packages/rest-hooks/src/react-integration/provider/__tests__/middleware.tsx
@@ -0,0 +1,200 @@
+import React from 'react';
+import { renderHook, act } from '@testing-library/react-hooks';
+import createEnhancedReducerHook from '../middleware';
+import { MiddlewareAPI } from '../../../types';
+
+function ignoreError(e: Event) {
+  e.preventDefault();
+}
+beforeEach(() => {
+  window.addEventListener('error', ignoreError);
+});
+afterEach(() => {
+  window.removeEventListener('error', ignoreError);
+});
+
+describe('createEnhancedReducerHook', () => {
+  const makeTestActionMiddleware = (test: Function) => () => {
+    return (next: any) => (action: any) => {
+      test(action);
+      return next(action);
+    };
+  };
+  const makeTestMiddleware = (spy: Function) => (methods: MiddlewareAPI) => {
+    spy(methods);
+    return (next: any) => (action: any) => next(action);
+  };
+  const dispatchingMiddleware = ({ dispatch }: MiddlewareAPI) => {
+    return (next: any) => (action: any) => {
+      if (action.type === 'dispatch') {
+        dispatch({ ...action, type: 'nothing' });
+      }
+      return next(action);
+    };
+  };
+  const makeStatefulMiddleware = ({
+    callBefore,
+    callAfter,
+  }: {
+    callBefore: Function;
+    callAfter: Function;
+  }) => ({ getState }: MiddlewareAPI) => {
+    return (next: any) => async (action: any) => {
+      callBefore(getState());
+      await next(action);
+      callAfter(getState());
+    };
+  };
+
+  test('runs through a single middleware', () => {
+    const faker = jest.fn();
+    const logger = makeTestActionMiddleware(faker);
+    const { result } = renderHook(() => {
+      const useEnhancedReducer = createEnhancedReducerHook(logger);
+      return useEnhancedReducer(state => state, {});
+    });
+    const [state, dispatch] = result.current;
+
+    expect(faker.mock.calls.length).toBe(0);
+    const action = { type: 5 };
+    act(() => {
+      dispatch(action);
+    });
+    expect(faker.mock.calls.length).toBe(1);
+    expect(faker.mock.calls[0][0]).toBe(action);
+    act(() => {
+      dispatch(action);
+    });
+    expect(faker.mock.calls.length).toBe(2);
+  });
+
+  it('wraps dispatch method with middleware once', () => {
+    const [faker, statefaker] = [jest.fn(), jest.fn()];
+    const methodspy = makeTestMiddleware(faker);
+    const statespy = makeTestMiddleware(({ getState }: MiddlewareAPI) =>
+      statefaker(getState()),
+    );
+
+    const { result } = renderHook(() => {
+      const useEnhancedReducer = createEnhancedReducerHook(methodspy, statespy);
+      return useEnhancedReducer(state => state, { double: 5 });
+    });
+    const [state, dispatch] = result.current;
+
+    const action = { type: 5 };
+    act(() => {
+      dispatch(action);
+      dispatch(action);
+    });
+
+    expect(faker.mock.calls.length).toEqual(1);
+
+    expect(faker.mock.calls[0][0]).toHaveProperty('getState');
+    expect(faker.mock.calls[0][0]).toHaveProperty('dispatch');
+
+    expect(statefaker.mock.calls[0][0]).toEqual({ double: 5 });
+  });
+
+  test('reducer to work properly', () => {
+    const logger = makeTestActionMiddleware(() => {});
+
+    const { result } = renderHook(() => {
+      const useEnhancedReducer = createEnhancedReducerHook(logger);
+      return useEnhancedReducer(
+        (state, action) => ({ ...state, omlet: action.payload }),
+        { eggs: 'bacon' },
+      );
+    });
+    let [state, dispatch] = result.current;
+    act(() => {
+      dispatch({ payload: 5 });
+    });
+    [state, dispatch] = result.current;
+    expect(state).toEqual({
+      eggs: 'bacon',
+      omlet: 5,
+    });
+    act(() => {
+      dispatch({ payload: 'chicken' });
+    });
+    [state, dispatch] = result.current;
+    expect(state).toEqual({
+      eggs: 'bacon',
+      omlet: 'chicken',
+    });
+  });
+
+  test('should work with middlewares that call dispatch', () => {
+    const faker = jest.fn();
+    const logger = makeTestActionMiddleware(faker);
+
+    const { result } = renderHook(() => {
+      const useEnhancedReducer = createEnhancedReducerHook(
+        logger,
+        dispatchingMiddleware,
+      );
+      return useEnhancedReducer(state => state, {});
+    });
+    const [state, dispatch] = result.current;
+    expect(faker.mock.calls.length).toBe(0);
+    let action: any = { type: 'hi' };
+    act(() => {
+      dispatch(action);
+    });
+    expect(faker.mock.calls.length).toBe(1);
+    expect(faker.mock.calls[0][0]).toBe(action);
+    action = { type: 'dispatch', payload: 5 };
+    act(() => {
+      dispatch(action);
+    });
+    expect(faker.mock.calls.length).toBe(3);
+    expect(faker.mock.calls[2][0]).toEqual({ type: 'nothing', payload: 5 });
+  });
+
+  test('should work with middlewares that getState()', async () => {
+    const callBefore = jest.fn();
+    const callAfter = jest.fn();
+    const logger = makeStatefulMiddleware({ callBefore, callAfter });
+
+    const reducer = (state: { counter: number }) => ({
+      ...state,
+      counter: state.counter + 1,
+    });
+    const { result } = renderHook(() => {
+      const useEnhancedReducer = createEnhancedReducerHook(logger);
+      return useEnhancedReducer(reducer, { counter: 0 });
+    });
+    let [state, dispatch] = result.current;
+    expect(callBefore.mock.calls.length).toBe(0);
+    let action: any = { type: 'hi' };
+    await act(() => {
+      return dispatch(action);
+    });
+    [state, dispatch] = result.current;
+    expect(callBefore.mock.calls.length).toBe(1);
+    expect(callAfter.mock.calls.length).toBe(1);
+    expect(callBefore.mock.calls[0][0]).toEqual({ counter: 0 });
+    expect(callAfter.mock.calls[0][0]).toEqual({ counter: 1 });
+    expect(callAfter.mock.calls[0][0]).toEqual(state);
+    action = { type: 'dispatch', payload: 5 };
+    await act(() => {
+      return dispatch(action);
+    });
+    expect(callBefore.mock.calls.length).toBe(2);
+    expect(callAfter.mock.calls.length).toBe(2);
+    expect(callBefore.mock.calls[1][0]).toEqual({ counter: 1 });
+    expect(callAfter.mock.calls[1][0]).toEqual({ counter: 2 });
+  });
+
+  it('warns when dispatching during middleware setup', () => {
+    function dispatchingMiddleware({ dispatch }: { dispatch: Function }) {
+      dispatch({ type: 'dispatch', payload: 5 });
+      return (next: Function) => (action: any) => next(action);
+    }
+    const { result } = renderHook(() => {
+      createEnhancedReducerHook(dispatchingMiddleware)(state => state, {});
+    });
+    expect(result.error).toBeDefined();
+    expect(result.error.message).toMatchSnapshot();
+  });
+});

diff --git a/packages/rest-hooks/src/react-integration/provider/__tests__/provider.tsx b/packages/rest-hooks/src/react-integration/provider/__tests__/provider.tsx
