@@ -0,0 +1,401 @@
+import nock from 'nock';
+
+import {
+  CoolerArticleResource,
+  UserResource,
+  UrlArticleResource,
+} from '../../__tests__/common';
+import { normalize } from '../normal';
+import Resource from '../Resource';
+import SimpleResource from '../SimpleResource';
+
+describe('Resource', () => {
+  it('should init', () => {
+    const resource = CoolerArticleResource.fromJS({
+      id: 5,
+      title: 'happy',
+      author: 5,
+    });
+    expect(resource.pk()).toBe(5);
+    expect(CoolerArticleResource.pk(resource)).toBe(5);
+    expect(resource.title).toBe('happy');
+    expect(resource.things).toBe('happy five');
+    expect(resource.url).toBe('http://test.com/article-cooler/5');
+    expect(resource.author).toBe(5);
+  });
+
+  it('should not init Resource itself', () => {
+    expect(() => Resource.fromJS({})).toThrow();
+  });
+
+  it('should work with `url` member', () => {
+    expect(() => UrlArticleResource.fromJS({})).not.toThrow();
+    expect(() => UrlArticleResource.fromJS({ url: 'five' })).not.toThrow();
+    const urlArticle = UrlArticleResource.fromJS({ url: 'five' });
+    expect(urlArticle.url).toBe('five');
+  });
+
+  it('should convert class to string', () => {
+    expect(CoolerArticleResource.toString()).toBeDefined();
+    expect(CoolerArticleResource.toString()).toMatchInlineSnapshot(
+      `"CoolerArticleResource::http://test.com/article-cooler/"`,
+    );
+  });
+
+  it('should render url property', () => {
+    const article = CoolerArticleResource.fromJS({
+      id: 5,
+      title: 'happy',
+      author: 5,
+    });
+    expect(article.url).toBe('http://test.com/article-cooler/5');
+  });
+
+  it('should render url property with non-trailing slash root', () => {
+    // Remove trailing slash in url root
+    CoolerArticleResource.urlRoot = 'http://test.com/article-cooler';
+    const article = CoolerArticleResource.fromJS({
+      id: 5,
+      title: 'happy',
+      author: 5,
+    });
+    expect(article.url).toBe('http://test.com/article-cooler/5');
+    // Reset for future tests
+    CoolerArticleResource.urlRoot = 'http://test.com/article-cooler/';
+  });
+
+  const [coolA, coolB, coolC] = [
+    CoolerArticleResource.fromJS({ title: 'great' }),
+    CoolerArticleResource.fromJS({ id: 5 }),
+    CoolerArticleResource.fromJS({}),
+  ];
+
+  describe('merge()', () => {
+    const c = CoolerArticleResource.merge(coolA, coolB);
+    it('works with partial', () => {
+      expect(c.things).toBeDefined();
+      expect(c.id).toBe(5);
+      expect(c.content).toBe('');
+      expect(c.title).toBe('great');
+      expect(c).toMatchInlineSnapshot(`
+        CoolerArticleResource {
+          "author": null,
+          "content": "",
+          "id": 5,
+          "tags": Array [],
+          "title": "great",
+        }
+      `);
+    });
+    it('works with definedObjects()', () => {
+      expect(c).toMatchInlineSnapshot(`
+        CoolerArticleResource {
+          "author": null,
+          "content": "",
+          "id": 5,
+          "tags": Array [],
+          "title": "great",
+        }
+      `);
+    });
+    it('does nothing with empty arg', () => {
+      expect(CoolerArticleResource.merge(c, coolC)).toEqual(c);
+    });
+  });
+
+  describe('hasDefined()', () => {
+    it('works ', () => {
+      expect(CoolerArticleResource.hasDefined(coolA, 'title')).toBe(true);
+      expect(CoolerArticleResource.hasDefined(coolA, 'author')).toBe(false);
+    });
+  });
+
+  describe('toObjectDefined()', () => {
+    it('works', () => {
+      expect(CoolerArticleResource.toObjectDefined(coolA))
+        .toMatchInlineSnapshot(`
+        Object {
+          "title": "great",
+        }
+      `);
+      expect(CoolerArticleResource.toObjectDefined(coolB))
+        .toMatchInlineSnapshot(`
+        Object {
+          "id": 5,
+        }
+      `);
+    });
+  });
+
+  describe('keysDefined()', () => {
+    it('works', () => {
+      expect(CoolerArticleResource.keysDefined(coolA)).toMatchInlineSnapshot(`
+        Array [
+          "title",
+        ]
+      `);
+      expect(CoolerArticleResource.keysDefined(coolB)).toMatchInlineSnapshot(`
+        Array [
+          "id",
+        ]
+      `);
+    });
+  });
+
+  describe('listUrl', () => {
+    it('should listUrl with an arg', () => {
+      expect(CoolerArticleResource.listUrl({ author: 5 })).toBe(
+        'http://test.com/article-cooler/?author=5',
+      );
+    });
+    it('should listUrl with no args', () => {
+      expect(CoolerArticleResource.listUrl({})).toBe(
+        'http://test.com/article-cooler/',
+      );
+    });
+    it('should sort consistently', () => {
+      expect(
+        CoolerArticleResource.listUrl({
+          z: 'alpha',
+          y: 'beta',
+          m: 'never',
+          a: 'sometimes',
+          c: 'again',
+        }),
+      ).toBe(
+        'http://test.com/article-cooler/?a=sometimes&c=again&m=never&y=beta&z=alpha',
+      );
+    });
+  });
+
+  it('should not include __ownerID when converting to JS', () => {
+    const json = { ...CoolerArticleResource.fromJS({}) };
+    expect(json).not.toHaveProperty('__ownerID');
+  });
+
+  it('should have __ownerID property on lookup', () => {
+    const r = CoolerArticleResource.fromJS({});
+    expect(Object.prototype.hasOwnProperty.call(r, '__ownerID')).toBe(true);
+  });
+
+  describe('static url', () => {
+    it('should use provided url parameter as value', () => {
+      const url = 'this is the url';
+      expect(UserResource.url({ url })).toBe(url);
+    });
+  });
+
+  describe('Resource.fetch()', () => {
+    const id = 5;
+    const idHtml = 6;
+    const payload = {
+      id,
+      title: 'happy',
+      author: 5,
+    };
+    const putResponseBody = {
+      id,
+      title: 'happy',
+      completed: true,
+    };
+    const patchPayload = {
+      title: 'happy',
+    };
+    const patchResponseBody = {
+      id,
+      title: 'happy',
+      completed: false,
+    };
+
+    beforeEach(() => {
+      nock('http://test.com')
+        .get(`/article-cooler/${payload.id}`)
+        .reply(200, payload);
+      nock('http://test.com')
+        .get(`/article-cooler/${idHtml}`)
+        .reply(200, '<body>this is html</body>');
+
+      nock('http://test.com')
+        .post('/article-cooler/')
+        .reply((uri, requestBody) => [
+          201,
+          requestBody,
+          { 'content-type': 'application/json' },
+        ]);
+      nock('http://test.com')
+        .put('/article-cooler/5')
+        .reply((uri, requestBody) => {
+          let body = requestBody as any;
+          if (typeof requestBody === 'string') {
+            body = JSON.parse(requestBody);
+          }
+          for (const key of Object.keys(CoolerArticleResource.fromJS({}))) {
+            if (key !== 'id' && !(key in body)) {
+              return [400, {}, { 'content-type': 'application/json' }];
+            }
+          }
+          return [200, putResponseBody, { 'content-type': 'application/json' }];
+        });
+      nock('http://test.com')
+        .patch('/article-cooler/5')
+        .reply(() => [
+          200,
+          patchResponseBody,
+          { 'content-type': 'application/json' },
+        ]);
+      nock('http://test.com')
+        .intercept('/article-cooler/5', 'DELETE')
+        .reply(200, {});
+    });
+
+    it('should throw with SimpleResource', () => {
+      expect(() =>
+        SimpleResource.fetch(
+          'get',
+          CoolerArticleResource.url({
+            id: payload.id,
+          }),
+        ),
+      ).toThrow();
+    });
+
+    it('should GET', async () => {
+      const article = await CoolerArticleResource.fetch(
+        'get',
+        CoolerArticleResource.url({
+          id: payload.id,
+        }),
+      );
+      expect(article).toBeDefined();
+      if (!article) {
+        throw new Error('ahh');
+      }
+      expect(article.title).toBe(payload.title);
+    });
+
+    it('should POST', async () => {
+      const payload2 = { id: 20, content: 'better task' };
+      const article = await CoolerArticleResource.fetch(
+        'post',
+        CoolerArticleResource.url(),
+        payload2,
+      );
+      expect(article).toMatchObject(payload2);
+    });
+
+    it('should DELETE', async () => {
+      const res = await CoolerArticleResource.fetch(
+        'delete',
+        CoolerArticleResource.url({
+          id: payload.id,
+        }),
+      );
+      expect(res).toEqual({});
+    });
+
+    it('should PUT', async () => {
+      const response = await CoolerArticleResource.fetch(
+        'put',
+        CoolerArticleResource.url(payload),
+        CoolerArticleResource.fromJS(payload),
+      );
+      expect(response).toEqual(putResponseBody);
+    });
+
+    it('should PATCH', async () => {
+      const response = await CoolerArticleResource.fetch(
+        'patch',
+        CoolerArticleResource.url({ id }),
+        patchPayload,
+      );
+      expect(response).toEqual(patchResponseBody);
+    });
+
+    it('should throw if response is not json', async () => {
+      await expect(
+        CoolerArticleResource.fetch(
+          'get',
+          CoolerArticleResource.url({ id: idHtml }),
+        ),
+      ).rejects.toMatchSnapshot();
+    });
+
+    it('should use fetchPlugin if defined', async () => {
+      class FetchResource extends CoolerArticleResource {
+        static fetchPlugin = jest.fn(a => a);
+      }
+      const article = await FetchResource.fetch(
+        'get',
+        FetchResource.url({
+          id: payload.id,
+        }),
+      );
+      expect(article).toBeDefined();
+      expect(FetchResource.fetchPlugin.mock.calls.length).toBeGreaterThan(0);
+    });
+  });
+
+  describe('getEntitySchema()', () => {
+    describe('merging', () => {
+      const nested = [
+        {
+          id: 5,
+          title: 'hi ho',
+          content: 'whatever',
+          tags: ['a', 'best', 'react'],
+          author: {
+            id: 23,
+            username: 'bob',
+            email: 'bob@bob.com',
+          },
+        },
+        {
+          id: 3,
+          title: 'the next time',
+          content: 'whatever',
+          author: {
+            id: 23,
+            username: 'charles',
+          },
+        },
+      ];
+      const { schema } = CoolerArticleResource.listWithUserRequest();
+      const normalized = normalize(nested, schema);
+
+      // TODO: fix normalize types so we know this is actuaally multiple things
+      const user: any = normalized.entities[UserResource.getKey()]['23'];
+      it('should include nested user', () => {
+        expect(user).toBeDefined();
+      });
+      it('should have user be UserResource type', () => {
+        expect(user).toBeInstanceOf(UserResource);
+      });
+      it('should take property of first if not set in second', () => {
+        expect(user.email).toBe('bob@bob.com');
+      });
+      it('should overwrite second properties over first', () => {
+        expect(user.username).toBe('charles');
+      });
+      it('should use default for unset propreties', () => {
+        expect(UserResource.hasDefined(user, 'isAdmin')).toBe(false);
+      });
+      it('should match snapshot', () => {
+        expect(normalized).toMatchSnapshot();
+      });
+    });
+
+    it('should throw a custom error if data does not include pk', () => {
+      const schema = CoolerArticleResource.getEntitySchema();
+      function normalizeBad() {
+        normalize({}, schema);
+      }
+      expect(normalizeBad).toThrowErrorMatchingInlineSnapshot(`
+"Missing usable resource key when normalizing response.
+
+This is likely due to a malformed response.
+Try inspecting the network response or fetch() return value.
+"
+`);
+    });
+  });
+});

diff --git a/packages/rest-hooks/src/state/__tests__/pollingSubscription.ts b/packages/rest-hooks/src/state/__tests__/pollingSubscription.ts
new file mode 100644
index 0000000..bfe9588
--- /dev/null
+++ b/packages/rest-hooks/src/state/__tests__/pollingSubscription.ts
@@ -0,0 +1,163 @@
+import PollingSubscription from '../PollingSubscription';
+import { PollingArticleResource } from '../../__tests__/common';
+
+function onError(e: any) {
+  e.preventDefault();
+}
+beforeAll(() => {
+  window.addEventListener('error', onError);
+});
+afterAll(() => {
+  window.removeEventListener('error', onError);
+});
+
+describe('PollingSubscription', () => {
+  const dispatch = jest.fn();
+  const a = () => Promise.resolve({ id: 5, title: 'hi' });
+  const fetch = jest.fn(a);
+  jest.useFakeTimers();
+
+  const sub = new PollingSubscription(
+    {
+      url: 'test.com',
+      schema: PollingArticleResource.getEntitySchema(),
+      fetch,
+      frequency: 5000,
+    },
+    dispatch,
+  );
+
+  it('should throw on undefined frequency in construction', () => {
+    expect(
+      () =>
+        new PollingSubscription(
+          {
+            url: 'test.com',
+            schema: PollingArticleResource.getEntitySchema(),
+            fetch,
+          },
+          dispatch,
+        ),
+    ).toThrow();
+  });
+
+  it('should not call immediately', () => {
+    expect(dispatch.mock.calls.length).toBe(0);
+  });
+
+  it('should call after period', () => {
+    jest.advanceTimersByTime(5000);
+    expect(dispatch.mock.calls.length).toBe(1);
+    expect(dispatch.mock.calls[0]).toMatchSnapshot();
+    jest.advanceTimersByTime(5000);
+    expect(dispatch.mock.calls.length).toBe(2);
+    expect(dispatch.mock.calls[1]).toMatchSnapshot();
+  });
+
+  describe('add()', () => {
+    it('should take smaller frequency when another is added', () => {
+      sub.add(1000);
+      jest.advanceTimersByTime(1000 * 4);
+      expect(dispatch.mock.calls.length).toBe(2 + 4);
+    });
+
+    it('should not change frequency if same is added', () => {
+      dispatch.mockClear();
+      sub.add(1000);
+      jest.advanceTimersByTime(1000 * 13);
+      expect(dispatch.mock.calls.length).toBe(13);
+    });
+
+    it('should not change frequency if larger is added', () => {
+      dispatch.mockClear();
+      sub.add(7000);
+      sub.add(8000);
+      jest.advanceTimersByTime(1000 * 13);
+      expect(dispatch.mock.calls.length).toBe(13);
+    });
+
+    it('should do nothing if frequency is undefined', () => {
+      dispatch.mockClear();
+      sub.add(undefined);
+      jest.advanceTimersByTime(1000 * 13);
+      expect(dispatch.mock.calls.length).toBe(13);
+    });
+  });
+
+  describe('remove()', () => {
+    it('should not change frequency if only partially removed', () => {
+      dispatch.mockClear();
+      sub.remove(1000);
+      jest.advanceTimersByTime(1000 * 13);
+      expect(dispatch.mock.calls.length).toBe(13);
+    });
+
+    it('should not change frequency if only larger removed', () => {
+      dispatch.mockClear();
+      sub.remove(7000);
+      jest.advanceTimersByTime(1000 * 13);
+      expect(dispatch.mock.calls.length).toBe(13);
+    });
+
+    it('should go back to fastest if smallest frequency is removed completely', () => {
+      sub.remove(1000);
+      jest.advanceTimersByTime(1000);
+      dispatch.mockClear();
+      jest.advanceTimersByTime(5000 * 13);
+      expect(dispatch.mock.calls.length).toBe(13);
+    });
+
+    it('should do nothing if frequency is not registered', () => {
+      const oldError = console.error;
+      const spy = (console.error = jest.fn());
+
+      sub.remove(1000);
+      dispatch.mockClear();
+      jest.advanceTimersByTime(5000 * 13);
+      expect(dispatch.mock.calls.length).toBe(13);
+
+      expect(spy.mock.calls[0]).toMatchInlineSnapshot(`
+        Array [
+          "Mismatched remove: 1000 is not subscribed for test.com",
+        ]
+      `);
+      console.error = oldError;
+    });
+
+    it('should do nothing if frequency is undefined', () => {
+      sub.remove(undefined);
+      dispatch.mockClear();
+      jest.advanceTimersByTime(5000 * 13);
+      expect(dispatch.mock.calls.length).toBe(13);
+    });
+
+    it('should return false until completely empty, then return true', () => {
+      const sub = new PollingSubscription(
+        {
+          url: 'test.com',
+          schema: PollingArticleResource.getEntitySchema(),
+          fetch,
+          frequency: 5000,
+        },
+        dispatch,
+      );
+      sub.add(5000);
+      sub.add(7000);
+      expect(sub.remove(5000)).toBe(false);
+      expect(sub.remove(5000)).toBe(false);
+      expect(sub.remove(7000)).toBe(true);
+    });
+  });
+
+  describe('cleanup()', () => {
+    it('should stop all timers', () => {
+      dispatch.mockClear();
+      sub.cleanup();
+      jest.advanceTimersByTime(5000 * 13);
+      expect(dispatch.mock.calls.length).toBe(0);
+    });
+    it('should be idempotent', () => {
+      sub.cleanup();
+    });
+  });
+});

diff --git a/packages/rest-hooks/src/state/__tests__/reducer.ts b/packages/rest-hooks/src/state/__tests__/reducer.ts
new file mode 100644
index 0000000..87d359f
--- /dev/null
+++ b/packages/rest-hooks/src/state/__tests__/reducer.ts
@@ -0,0 +1,481 @@
+import {
+  ArticleResource,
+  ArticleResourceWithOtherListUrl,
+  PaginatedArticleResource,
+} from '../../__tests__/common';
+import reducer from '../reducer';
+import {
+  FetchAction,
+  RPCAction,
+  ReceiveAction,
+  PurgeAction,
+  ResetAction,
+  InvalidateAction,
+  UpdateFunction,
+} from '../../types';
+
+describe('reducer', () => {
+  describe('singles', () => {
+    const id = 20;
+    const payload = { id, title: 'hi', content: 'this is the content' };
+    const action: ReceiveAction<typeof payload> = {
+      type: 'rest-hooks/receive',
+      payload,
+      meta: {
+        schema: ArticleResource.getEntitySchema(),
+        url: ArticleResource.url({ id }),
+        date: 5000000000,
+        expiresAt: 5000500000,
+      },
+    };
+    const partialResultAction = {
+      ...action,
+      payload: { id, title: 'hello' },
+    };
+    const iniState = {
+      entities: {},
+      results: {},
+      meta: {},
+    };
+    const newState = reducer(iniState, action);
+    it('should update state correctly', () => {
+      expect(newState).toMatchSnapshot();
+    });
+    it('should overwrite existing entity', () => {
+      const getEntity = (state: any): ArticleResource =>
+        state.entities[ArticleResource.getKey()][
+          `${ArticleResource.pk(action.payload)}`
+        ];
+      const prevEntity = getEntity(newState);
+      expect(prevEntity).toBeDefined();
+      const nextState = reducer(newState, action);
+      const nextEntity = getEntity(nextState);
+      expect(nextEntity).not.toBe(prevEntity);
+      expect(nextEntity).toBeDefined();
+    });
+    it('should merge partial entity with existing entity', () => {
+      const getEntity = (state: any): ArticleResource =>
+        state.entities[ArticleResource.getKey()][
+          `${ArticleResource.pk(action.payload)}`
+        ];
+      const prevEntity = getEntity(newState);
+      expect(prevEntity).toBeDefined();
+      const nextState = reducer(newState, partialResultAction);
+      const nextEntity = getEntity(nextState);
+      expect(nextEntity).not.toBe(prevEntity);
+      expect(nextEntity).toBeDefined();
+
+      expect(nextEntity.title).not.toBe(prevEntity.title);
+      expect(nextEntity.title).toBe(partialResultAction.payload.title);
+
+      expect(nextEntity.content).toBe(prevEntity.content);
+      expect(nextEntity.content).not.toBe(undefined);
+    });
+  });
+  it('mutate should never change results', () => {
+    const id = 20;
+    const payload = { id, title: 'hi', content: 'this is the content' };
+    const action: RPCAction = {
+      type: 'rest-hooks/rpc',
+      payload,
+      meta: {
+        schema: ArticleResource.getEntitySchema(),
+        url: ArticleResource.listUrl(payload),
+      },
+    };
+    const iniState = {
+      entities: {},
+      results: { abc: '5' },
+      meta: {},
+    };
+    const newState = reducer(iniState, action);
+    expect(newState.results).toBe(iniState.results);
+  });
+  it('purge should delete entities', () => {
+    const id = 20;
+    const action: PurgeAction = {
+      type: 'rest-hooks/purge',
+      meta: {
+        schema: ArticleResource.getEntitySchema(),
+        url: id.toString(),
+      },
+    };
+    const iniState: any = {
+      entities: {
+        [ArticleResource.getKey()]: {
+          '10': ArticleResource.fromJS({ id: 10 }),
+          '20': ArticleResource.fromJS({ id: 20 }),
+          '25': ArticleResource.fromJS({ id: 25 }),
+        },
+        [PaginatedArticleResource.getKey()]: {
+          hi: PaginatedArticleResource.fromJS({ id: 5 }),
+        },
+        '5': undefined,
+      },
+      results: { abc: '20' },
+      meta: {},
+    };
+    const newState = reducer(iniState, action);
+    expect(newState.results).toBe(iniState.results);
+    expect(newState.meta).toBe(iniState.meta);
+    const expectedEntities = { ...iniState.entities[ArticleResource.getKey()] };
+    delete expectedEntities['20'];
+    expect(newState.entities[ArticleResource.getKey()]).toEqual(
+      expectedEntities,
+    );
+  });
+
+  describe('optimistic update', () => {
+    describe('Update on get (pagination use case)', () => {
+      const shape = PaginatedArticleResource.listShape();
+      function makeOptimisticAction(
+        payload: {
+          results: Partial<PaginatedArticleResource>[];
+        },
+        updaters: {
+          [key: string]: UpdateFunction<
+            typeof shape['schema'],
+            typeof shape['schema']
+          >;
+        },
+      ) {
+        return {
+          type: 'rest-hooks/receive' as const,
+          payload,
+          meta: {
+            schema: PaginatedArticleResource.listShape().schema,
+            url: PaginatedArticleResource.listShape().getFetchKey({
+              cursor: 2,
+            }),
+            updaters,
+            date: 5000000000,
+            expiresAt: 5000500000,
+          },
+        };
+      }
+
+      const insertAfterUpdater = <T extends { results?: string[] } | undefined>(
+        newPage: { results: string[] },
+        oldResults: T,
+      ) => ({
+        ...oldResults,
+        results: [...(oldResults?.results || []), ...newPage.results],
+      });
+
+      const insertBeforeUpdater = <
+        T extends { results?: string[] } | undefined
+      >(
+        newPage: { results: string[] },
+        oldResults: T,
+      ) => ({
+        ...oldResults,
+        results: [...newPage.results, ...(oldResults?.results || [])],
+      });
+
+      const iniState: any = {
+        entities: {
+          [PaginatedArticleResource.getKey()]: {
+            '10': PaginatedArticleResource.fromJS({ id: 10 }),
+          },
+        },
+        results: {
+          [PaginatedArticleResource.listUrl()]: { results: ['10'] },
+        },
+        meta: {},
+      };
+
+      it('should insert a new page of resources into a list request', () => {
+        const newState = reducer(
+          iniState,
+          makeOptimisticAction(
+            { results: [{ id: 11 }, { id: 12 }] },
+            {
+              [PaginatedArticleResource.listUrl()]: insertAfterUpdater,
+            },
+          ),
+        );
+        expect(
+          newState.results[PaginatedArticleResource.listUrl()],
+        ).toStrictEqual({ results: ['10', '11', '12'] });
+      });
+
+      it('should insert correctly into the beginning of the list request', () => {
+        const newState = reducer(
+          iniState,
+          makeOptimisticAction(
+            { results: [{ id: 11 }, { id: 12 }] },
+            {
+              [PaginatedArticleResource.listUrl()]: insertBeforeUpdater,
+            },
+          ),
+        );
+        expect(
+          newState.results[PaginatedArticleResource.listUrl()],
+        ).toStrictEqual({ results: ['11', '12', '10'] });
+      });
+    });
+
+    describe('rpc update on create', () => {
+      const createShape = ArticleResource.createShape();
+      function makeOptimisticAction(
+        payload: Partial<ArticleResource>,
+        updaters: {
+          [key: string]: UpdateFunction<
+            typeof createShape['schema'],
+            ReturnType<typeof ArticleResource.getEntitySchema>[]
+          >;
+        },
+      ) {
+        return {
+          type: 'rest-hooks/rpc' as const,
+          payload,
+          meta: {
+            schema: ArticleResource.getEntitySchema(),
+            url: ArticleResource.createShape().getFetchKey({}),
+            updaters,
+          },
+        };
+      }
+
+      const insertAfterUpdater = (
+        result: string,
+        oldResults: string[] | undefined,
+      ) => [...(oldResults || []), result];
+
+      const insertBeforeUpdater = (
+        result: string,
+        oldResults: string[] | undefined,
+      ) => [result, ...(oldResults || [])];
+
+      const iniState: any = {
+        entities: {
+          [ArticleResourceWithOtherListUrl.getKey()]: {
+            '10': ArticleResourceWithOtherListUrl.fromJS({ id: 10 }),
+            '21': ArticleResourceWithOtherListUrl.fromJS({ id: 21 }),
+          },
+        },
+        results: {
+          [ArticleResourceWithOtherListUrl.listUrl()]: ['10'],
+          [ArticleResourceWithOtherListUrl.otherListUrl()]: ['21'],
+        },
+        meta: {},
+      };
+
+      it('it should run inserts for a simple resource after the existing list entities', () => {
+        const newState = reducer(
+          iniState,
+          makeOptimisticAction(
+            { id: 11 },
+            {
+              [ArticleResource.listUrl()]: insertAfterUpdater,
+            },
+          ),
+        );
+        expect(newState.results[ArticleResource.listUrl()]).toStrictEqual([
+          '10',
+          '11',
+        ]);
+      });
+
+      it('it should run inserts for a simple resource before the existing list entities', () => {
+        const newState = reducer(
+          iniState,
+          makeOptimisticAction(
+            { id: 11 },
+            {
+              [ArticleResource.listUrl()]: insertBeforeUpdater,
+            },
+          ),
+        );
+        expect(newState.results[ArticleResource.listUrl()]).toStrictEqual([
+          '11',
+          '10',
+        ]);
+      });
+
+      it('it runs inserts for multiple updaters', () => {
+        const newState = reducer(
+          iniState,
+          makeOptimisticAction(
+            { id: 11 },
+            {
+              [ArticleResourceWithOtherListUrl.listUrl()]: insertAfterUpdater,
+              [ArticleResourceWithOtherListUrl.otherListUrl()]: insertAfterUpdater,
+            },
+          ),
+        );
+        expect(
+          newState.results[ArticleResourceWithOtherListUrl.listUrl()],
+        ).toStrictEqual(['10', '11']);
+        expect(
+          newState.results[ArticleResourceWithOtherListUrl.otherListUrl()],
+        ).toStrictEqual(['21', '11']);
+      });
+    });
+  });
+
+  it('invalidates resources correctly', () => {
+    const id = 20;
+    const action: InvalidateAction = {
+      type: 'rest-hooks/invalidate',
+      meta: {
+        url: id.toString(),
+      },
+    };
+    const iniState: any = {
+      entities: {
+        [ArticleResource.getKey()]: {
+          '10': ArticleResource.fromJS({ id: 10 }),
+          '20': ArticleResource.fromJS({ id: 20 }),
+          '25': ArticleResource.fromJS({ id: 25 }),
+        },
+        [PaginatedArticleResource.getKey()]: {
+          hi: PaginatedArticleResource.fromJS({ id: 5 }),
+        },
+        '5': undefined,
+      },
+      results: { abc: '20' },
+      meta: {
+        '20': {
+          expiresAt: 500,
+        },
+        '25': {
+          expiresAt: 1000,
+        },
+      },
+    };
+    const newState = reducer(iniState, action);
+    expect(newState.results).toBe(iniState.results);
+    expect(newState.entities).toBe(iniState.entities);
+    const expectedMeta = { ...iniState.meta };
+    expectedMeta['20'] = { expiresAt: 0 };
+    expect(newState.meta).toEqual(expectedMeta);
+  });
+  it('should set error in meta for "receive"', () => {
+    const id = 20;
+    const error = new Error('hi');
+    const action: ReceiveAction = {
+      type: 'rest-hooks/receive',
+      payload: error,
+      meta: {
+        schema: ArticleResource.getEntitySchema(),
+        url: ArticleResource.url({ id }),
+        date: 5000000000,
+        expiresAt: 5000500000,
+      },
+      error: true,
+    };
+    const iniState = {
+      entities: {},
+      results: {},
+      meta: {},
+    };
+    const newState = reducer(iniState, action);
+    expect(newState).toMatchSnapshot();
+  });
+  it('should not modify state on error for "rpc"', () => {
+    const id = 20;
+    const error = new Error('hi');
+    const action: RPCAction = {
+      type: 'rest-hooks/rpc',
+      payload: error,
+      meta: {
+        schema: ArticleResource.getEntitySchema(),
+        url: ArticleResource.url({ id }),
+      },
+      error: true,
+    };
+    const iniState = {
+      entities: {},
+      results: {},
+      meta: {},
+    };
+    const newState = reducer(iniState, action);
+    expect(newState).toEqual(iniState);
+  });
+  it('should not delete on error for "purge"', () => {
+    const id = 20;
+    const error = new Error('hi');
+    const action: PurgeAction = {
+      type: 'rest-hooks/purge',
+      payload: error,
+      meta: {
+        schema: ArticleResource.getEntitySchema(),
+        url: ArticleResource.url({ id }),
+      },
+      error: true,
+    };
+    const iniState = {
+      entities: {
+        [ArticleResource.getKey()]: {
+          [id]: ArticleResource.fromJS({}),
+        },
+      },
+      results: {
+        [ArticleResource.url({ id })]: id,
+      },
+      meta: {},
+    };
+    const newState = reducer(iniState, action);
+    expect(newState).toEqual(iniState);
+  });
+  it('rest-hooks/fetch should console.warn()', () => {
+    global.console.warn = jest.fn();
+    const action: FetchAction = {
+      type: 'rest-hooks/fetch',
+      payload: () => new Promise<any>(() => null),
+      meta: {
+        schema: ArticleResource.getEntitySchema(),
+        url: ArticleResource.url({ id: 5 }),
+        responseType: 'rest-hooks/rpc',
+        throttle: true,
+        reject: (v: any) => null,
+        resolve: (v: any) => null,
+      },
+    };
+    const iniState = {
+      entities: {},
+      results: { abc: '5' },
+      meta: {},
+    };
+    const newState = reducer(iniState, action);
+    expect(newState).toBe(iniState);
+    expect((global.console.warn as jest.Mock).mock.calls.length).toBe(2);
+  });
+  it('other types should do nothing', () => {
+    const action: any = {
+      type: 'whatever',
+    };
+    const iniState = {
+      entities: {},
+      results: { abc: '5' },
+      meta: {},
+    };
+    const newState = reducer(iniState, action);
+    expect(newState).toBe(iniState);
+  });
+  it('reset should delete all entries', () => {
+    const action: ResetAction = {
+      type: 'rest-hooks/reset',
+    };
+    const iniState: any = {
+      entities: {
+        [ArticleResource.getKey()]: {
+          '10': ArticleResource.fromJS({ id: 10 }),
+          '20': ArticleResource.fromJS({ id: 20 }),
+          '25': ArticleResource.fromJS({ id: 25 }),
+        },
+        [PaginatedArticleResource.getKey()]: {
+          hi: PaginatedArticleResource.fromJS({ id: 5 }),
+        },
+        '5': undefined,
+      },
+      results: { abc: '20' },
+      meta: {},
+    };
+    const newState = reducer(iniState, action);
+    expect(newState.results).toEqual({});
+    expect(newState.meta).toEqual({});
+    expect(newState.entities).toEqual({});
+  });
+});

