+        dataExpiryLength: 7,
+      });
+      const ov = await getOverride({ id: '5' });
+      ov.author;
+      // @ts-expect-error
+      ov.asdf;
+    });
+
+    it('should maintain existing type on .extend() when process is not supplied but path is', async () => {
+      const getOverride = getArticle.extend({
+        path: '/:a/:b',
+      });
+      async () => {
+        const ov = await getOverride({ a: '5', b: '7' });
+        ov.author;
+        // @ts-expect-error
+        ov.asdf;
+      };
+    });
+
+    it('should override existing type on .extend() when path is also supplied', async () => {
+      const getOverride = getArticle.extend({
+        path: '/:a/:b',
+        process(value: any, param: any): { asdf: string } {
+          return value;
+        },
+      });
+      async () => {
+        const ov = await getOverride({ a: '5', b: '7' });
+        ov.asdf;
+        // @ts-expect-error
+        ov.author;
+      };
+      () => useSuspense(getOverride, { a: '5', b: '7' }).asdf;
+      // @ts-expect-error
+      () => useSuspense(getOverride, { a: '5', b: '7' }).content;
+    });
+  });
+
+  it('extend options should match function of path set', () => {
+    const endpoint = new RestEndpoint({
+      sideEffect: true,
+      path: 'http\\://test.com/article-cooler/:id',
+      body: 0 as any,
+      schema: CoolerArticle,
+      getOptimisticResponse(snap, params, body) {
+        params.id;
+        // @ts-expect-error
+        params.two;
+
+        body.hi;
+      },
+    }).extend({
+      path: '/:group/next/:two',
+      body: undefined,
+      getOptimisticResponse(snap, params) {
+        params.two;
+        params.group;
+        // @ts-expect-error
+        params.id;
+      },
+    });
+  });
+});
+
+describe('RestEndpoint.fetch()', () => {
+  const id = 5;
+  const idHtml = 6;
+  const idNoContent = 7;
+  const payload = {
+    id,
+    title: 'happy',
+    author: User.fromJS({ id: 5 }),
+  };
+  const putResponseBody = {
+    id,
+    title: 'happy',
+    completed: true,
+  };
+  const patchPayload = {
+    title: 'happy',
+  };
+  const patchResponseBody = {
+    id,
+    title: 'happy',
+    completed: false,
+  };
+
+  beforeEach(() => {
+    nock(/.*/)
+      .defaultReplyHeaders({
+        'Access-Control-Allow-Origin': '*',
+        'Content-Type': 'application/json',
+      })
+      .options(/.*/)
+      .reply(200)
+      .get(`/article-cooler/${payload.id}`)
+      .reply(200, payload)
+      .get(`/article-cooler/${idHtml}`)
+      .reply(200, '<body>this is html</body>')
+      .get(`/article-cooler/${idNoContent}`)
+      .reply(204, '')
+      .post('/article-cooler')
+      .reply((uri, requestBody) => [
+        201,
+        requestBody,
+        { 'content-type': 'application/json' },
+      ])
+      .put('/article-cooler/5')
+      .reply((uri, requestBody) => {
+        let body = requestBody as any;
+        if (typeof requestBody === 'string') {
+          body = JSON.parse(requestBody);
+        }
+        for (const key of Object.keys(CoolerArticle.fromJS({}))) {
+          if (key !== 'id' && !(key in body)) {
+            return [400, {}, { 'content-type': 'application/json' }];
+          }
+        }
+        return [200, putResponseBody, { 'content-type': 'application/json' }];
+      })
+      .patch('/article-cooler/5')
+      .reply(() => [
+        200,
+        patchResponseBody,
+        { 'content-type': 'application/json' },
+      ])
+      .intercept('/article-cooler/5', 'DELETE')
+      .reply(200, {});
+  });
+
+  afterEach(() => {
+    nock.cleanAll();
+  });
+
+  it('should GET', async () => {
+    const article = await CoolerArticleResource.get({
+      id: payload.id,
+    });
+    expect(article).toBeDefined();
+    if (!article) {
+      throw new Error('ahh');
+    }
+    expect(article.title).toBe(payload.title);
+  });
+
+  it('should POST', async () => {
+    const payload2 = { id: 20, content: 'better task' };
+    const article = await CoolerArticleResource.create(payload2);
+    expect(article).toMatchObject(payload2);
+  });
+
+  it('should PUT with multipart form data', async () => {
+    const payload2 = { id: 500, content: 'another' };
+    let lastRequest: any;
+    nock(/.*/)
+      .defaultReplyHeaders({
+        'Access-Control-Allow-Origin': '*',
+      })
+      .put('/article-cooler/500')
+      .reply(function (uri, requestBody) {
+        lastRequest = this.req;
+        return [201, payload2, { 'Content-Type': 'application/json' }];
+      });
+    const newPhoto = new Blob();
+    const body = new FormData();
+    body.append('photo', newPhoto);
+
+    const article = await CoolerArticleResource.update.extend({
+      path: CoolerArticleResource.update.path,
+      body: new FormData(),
+    })({ id: '500' }, body);
+    expect(lastRequest.headers['content-type']).toContain(
+      'multipart/form-data',
+    );
+    expect(article).toMatchObject(payload2);
+  });
+
+  it('should DELETE', async () => {
+    const res = await CoolerArticleResource.delete({
+      id: payload.id,
+    });
+    expect(res).toEqual({ id });
+  });
+
+  it('should PUT', async () => {
+    const response = await CoolerArticleResource.update(
+      { id: payload.id },
+      { ...CoolerArticle.fromJS(payload) },
+    );
+    expect(response).toEqual(putResponseBody);
+  });
+
+  it('should PATCH', async () => {
+    const response = await CoolerArticleResource.partialUpdate(
+      { id },
+      patchPayload,
+    );
+    expect(response).toEqual(patchResponseBody);
+  });
+
+  it('should throw if response is not json', async () => {
+    let error: any;
+    try {
+      await CoolerArticleResource.get({ id: idHtml });
+    } catch (e) {
+      error = e;
+    }
+    expect(error).toBeDefined();
+    // This is very weird, but we're forced to use node-fetch for react native
+    // node-fetch doesn't handle errors consistently with normal fetch implementations, so this won't work
+    // react-native itself should match this correctly however.
+    if (typeof window !== 'undefined') expect(error.status).toBe(400);
+  });
+
+  it('should throw if network is down', async () => {
+    const oldError = console.error;
+    console.error = () => {};
+
+    const id = 10;
+    nock(/.*/)
+      .defaultReplyHeaders({
+        'Access-Control-Allow-Origin': '*',
+        'Content-Type': 'application/json',
+      })
+      .get(`/article-cooler/${id}`)
+      .replyWithError(new TypeError('Network Down'));
+
+    let error: any;
+    try {
+      await CoolerArticleResource.get({ id });
+    } catch (e) {
+      error = e;
+    }
+    expect(error).toBeDefined();
+    expect(error.status).toBe(500);
+
+    // eslint-disable-next-line require-atomic-updates
+    console.error = oldError;
+  });
+
+  it('should return raw response if status is 204 No Content', async () => {
+    const res = await CoolerArticleResource.get({ id: idNoContent });
+    expect(res).toBe(null);
+  });
+
+  it('should reject if content-type is not json with schema', async () => {
+    const id = 8;
+    const text = '<body>this is html</body>';
+    nock(/.*/)
+      .defaultReplyHeaders({
+        'Access-Control-Allow-Origin': '*',
+        'Content-Type': 'application/json',
+      })
+      .get(`/article-cooler/${id}`)
+      .reply(200, text, { 'content-type': 'html/text' });
+
+    await expect(
+      async () => await CoolerArticleResource.get({ id }),
+    ).rejects.toMatchSnapshot();
+  });
+
+  it('should reject if content-type does not exist with schema', async () => {
+    const id = 10;
+    const text = '<body>this is html</body>';
+    nock(/.*/)
+      .defaultReplyHeaders({
+        'Access-Control-Allow-Origin': '*',
+      })
+      .get(`/article-cooler/${id}`)
+      .reply(200, text, {});
+
+    await expect(
+      async () => await CoolerArticleResource.get({ id }),
+    ).rejects.toMatchSnapshot();
+  });
+
+  it('should return text if content-type is not json with no schema', async () => {
+    const id = 8;
+    const text = '<body>this is html</body>';
+    nock(/.*/)
+      .defaultReplyHeaders({
+        'Access-Control-Allow-Origin': '*',
+        'Content-Type': 'application/json',
+      })
+      .get(`/article-cooler/${id}`)
+      .reply(200, text, { 'content-type': 'html/text' });
+
+    const res = await CoolerArticleResource.get.extend({ schema: undefined })({
+      id,
+    });
+    expect(res).toBe('<body>this is html</body>');
+  });
+
+  it('should return text if content-type does not exist with no schema', async () => {
+    const id = 10;
+    const text = '<body>this is html</body>';
+    nock(/.*/)
+      .defaultReplyHeaders({
+        'Access-Control-Allow-Origin': '*',
+      })
+      .get(`/article-cooler/${id}`)
+      .reply(200, text, {});
+
+    const res = await CoolerArticleResource.get.extend({ schema: undefined })({
+      id,
+    });
+    expect(res).toBe(text);
+  });
+
+  it('should reject with custom message if content type is set but json parsable', async () => {
+    const id = 8;
+    nock(/.*/)
+      .defaultReplyHeaders({
+        'Access-Control-Allow-Origin': '*',
+        'Content-Type': 'text',
+      })
+      .get(`/article-cooler/${id}`)
+      .reply(200, { id, title: 'hi' }, {});
+
+    await expect(
+      async () => await CoolerArticleResource.get({ id }),
+    ).rejects.toMatchSnapshot();
+  });
+
+  it('should still work with empty content-type', async () => {
+    const id = 8;
+    nock(/.*/)
+      .defaultReplyHeaders({
+        'Access-Control-Allow-Origin': '*',
+      })
+      .get(`/article-cooler/${id}`)
+      .reply(200, { id, title: 'hi' });
+
+    const res = await CoolerArticleResource.get({
+      id,
+    });
+    expect(res).toEqual({ id, title: 'hi' });
+  });
+});
+const proto = Object.prototype;
+const gpo = Object.getPrototypeOf;
+
+function isPojo(obj: unknown): obj is Record<string, any> {
+  if (obj === null || typeof obj !== 'object') {
+    return false;
+  }
+  return gpo(obj) === proto;
+}

diff --git a/packages/react/src/next/__tests__/fetch.tsx b/packages/react/src/next/__tests__/fetch.tsx
new file mode 100644
index 0000000..6562f44
--- /dev/null
+++ b/packages/react/src/next/__tests__/fetch.tsx
@@ -0,0 +1,291 @@
+import { ResolveType } from '@rest-hooks/core';
+import { CacheProvider } from '@rest-hooks/react';
+import { CacheProvider as ExternalCacheProvider } from '@rest-hooks/redux';
+import { act } from '@testing-library/react-hooks';
+import { CoolerArticle, FutureArticleResource } from '__tests__/new';
+import nock from 'nock';
+
+import { useCache, useSuspense } from '../..';
+// relative imports to avoid circular dependency in tsconfig references
+import { makeRenderRestHook, FixtureEndpoint } from '../../../../test';
+import useController from '../useController';
+
+export const payload = {
+  id: 5,
+  title: 'hi ho',
+  content: 'whatever',
+  tags: ['a', 'best', 'react'],
+};
+
+export const createPayload = {
+  id: 1,
+  title: 'hi ho',
+  content: 'whatever',
+  tags: ['a', 'best', 'react'],
+};
+
+export const nested = [
+  {
+    id: 5,
+    title: 'hi ho',
+    content: 'whatever',
+    tags: ['a', 'best', 'react'],
+    author: {
+      id: 23,
+      username: 'bob',
+    },
+  },
+  {
+    id: 3,
+    title: 'the next time',
+    content: 'whatever',
+    author: {
+      id: 23,
+      username: 'charles',
+      email: 'bob@bob.com',
+    },
+  },
+];
+
+describe.each([
+  ['CacheProvider', CacheProvider],
+  ['ExternalCacheProvider', ExternalCacheProvider],
+] as const)(`%s`, (_, makeProvider) => {
+  // TODO: add nested resource test case that has multiple partials to test merge functionality
+
+  let renderRestHook: ReturnType<typeof makeRenderRestHook>;
+  let mynock: nock.Scope;
+
+  beforeEach(() => {
+    nock(/.*/)
+      .persist()
+      .defaultReplyHeaders({
+        'Access-Control-Allow-Origin': '*',
+        'Content-Type': 'application/json',
+      })
+      .options(/.*/)
+      .reply(200)
+      .get(`/article-cooler/${payload.id}`)
+      .reply(200, payload)
+      .delete(`/article-cooler/${payload.id}`)
+      .reply(204, '')
+      .delete(`/article/${payload.id}`)
+      .reply(200, {})
+      .get(`/article-cooler/0`)
+      .reply(403, {})
+      .get(`/article-cooler/666`)
+      .reply(200, '')
+      .get(`/article-cooler`)
+      .reply(200, nested)
+      .post(`/article-cooler`)
+      .reply(200, createPayload);
+
+    mynock = nock(/.*/).defaultReplyHeaders({
+      'Access-Control-Allow-Origin': '*',
+      'Content-Type': 'application/json',
+    });
+  });
+
+  afterEach(() => {
+    nock.cleanAll();
+  });
+
+  beforeEach(() => {
+    renderRestHook = makeRenderRestHook(makeProvider);
+  });
+
+  let errorspy: jest.SpyInstance;
+  beforeEach(() => {
+    errorspy = jest.spyOn(global.console, 'error');
+  });
+  afterEach(() => {
+    errorspy.mockRestore();
+  });
+
+  it('should fetch', async () => {
+    const { result } = renderRestHook(() => {
+      return {
+        data: useCache(FutureArticleResource.get, payload.id),
+        fetch: useController().fetch,
+      };
+    });
+    expect(result.current.data).toBeUndefined();
+    result.current.fetch(FutureArticleResource.get, payload.id);
+    result.current.fetch(FutureArticleResource.get, payload.id);
+    result.current.fetch(FutureArticleResource.get, payload.id);
+    const response = await result.current.fetch(
+      FutureArticleResource.get,
+      payload.id,
+    );
+    expect(result.current.data).toBeDefined();
+    expect(result.current.data?.content).toEqual(payload.content);
+    expect(response).toEqual(CoolerArticle.fromJS(payload));
+    expect(response.content).toBe(payload.content);
+
+    // @ts-expect-error
+    () => response.slkdf;
+
+    // type tests
+    // TODO: move these to own unit tests if/when applicable
+    () => {
+      // @ts-expect-error
+      result.current.fetch(FutureArticleResource.get);
+      // @ts-expect-error
+      result.current.fetch(FutureArticleResource.get, {
+        id: payload.id,
+      });
+      result.current.fetch(FutureArticleResource.create, payload);
+      // @ts-expect-error
+      result.current.fetch(FutureArticleResource.create, {}, payload);
+      result.current.fetch(FutureArticleResource.update, payload.id, payload);
+      // @ts-expect-error
+      result.current.fetch(FutureArticleResource.update, payload);
+    };
+  });
+
+  it('should fetch with resolver', async () => {
+    // we use this id because it is not nock'd
+    const id = 10000;
+    const fixture = {
+      endpoint: FutureArticleResource.get,
+      args: [10000],
+      response: payload,
+    };
+    const { result } = renderRestHook(
+      () => {
+        return {
+          data: useCache(FutureArticleResource.get, id),
+          fetch: useController().fetch,
+        };
+      },
+      { resolverFixtures: [fixture] },
+    );
+    expect(result.current.data).toBeUndefined();
+    result.current.fetch(FutureArticleResource.get, id);
+    result.current.fetch(FutureArticleResource.get, id);
+    result.current.fetch(FutureArticleResource.get, id);
+    await result.current.fetch(FutureArticleResource.get, id);
+  });
+
+  it('should update on create', async () => {
+    const endpoint = FutureArticleResource.create;
+    const response: ResolveType<typeof endpoint> = createPayload;
+    const fixtures: FixtureEndpoint[] = [
+      {
+        endpoint,
+        args: [{ id: 1 }],
+        response,
+      },
+    ];
+    // use nock, and use resolver
+    for (const resolverFixtures of [undefined, fixtures]) {
+      const { result, waitForNextUpdate } = renderRestHook(
+        () => {
+          const articles = useSuspense(FutureArticleResource.getList);
+          const fetch = useController().fetch;
+          return { articles, fetch };
+        },
+        { resolverFixtures },
+      );
+      await waitForNextUpdate();
+      await act(async () => {
+        const article = await result.current.fetch(
+          FutureArticleResource.create,
+          {
+            id: 1,
+          },
+        );
+        article.content;
+        // @ts-expect-error
+        article.asdf;
+        article.pk();
+      });
+
+      expect(result.current.articles.map(({ id }) => id)).toEqual([1, 5, 3]);
+    }
+  });
+
+  it('should log error message when user update method throws', async () => {
+    const endpoint = FutureArticleResource.create.extend({
+      update: () => {
+        throw new Error('usererror');
+      },
+    });
+    const response: ResolveType<typeof endpoint> = createPayload;
+    const fixtures: FixtureEndpoint[] = [
+      {
+        endpoint,
+        args: [{ id: 1 }],
+        response,
+      },
+    ];
+    const { result, waitForNextUpdate } = renderRestHook(
+      () => {
+        const articles = useSuspense(FutureArticleResource.getList);
+        const fetch = useController().fetch;
+        return { articles, fetch };
+      },
+      { resolverFixtures: fixtures },
+    );
+    await waitForNextUpdate();
+    await act(async () => {
+      await result.current.fetch(endpoint, {
+        id: 1,
+      });
+    }),
+      // still keeps old list
+      expect(result.current.articles.map(({ id }) => id)).toEqual([5, 3]);
+
+    expect(errorspy.mock.calls).toMatchSnapshot();
+  });
+
+  it('should not suspend once deleted and redirected at same time', async () => {
+    const temppayload = {
+      ...payload,
+      id: 1234,
+    };
+    mynock
+      .get(`/article-cooler/${temppayload.id}`)
+      .reply(200, temppayload)
+      .delete(`/article-cooler/${temppayload.id}`)
+      .reply(204, '');
+    const throws: Promise<any>[] = [];
+    const { result, waitForNextUpdate, rerender } = renderRestHook(
+      ({ id }) => {
+        try {
+          return [
+            useSuspense(FutureArticleResource.get, id) ?? null,
+            useController().fetch,
+          ] as const;
+        } catch (e: any) {
+          if (typeof e.then === 'function') {
+            if (e !== throws[throws.length - 1]) {
+              throws.push(e);
+            }
+          }
+          throw e;
+        }
+      },
+      { initialProps: { id: temppayload.id as number | null } },
+    );
+    expect(result.current).toBeUndefined();
+    await waitForNextUpdate();
+    const [data, fetch] = result.current;
+    expect(data).toBeInstanceOf(CoolerArticle);
+    expect(data?.title).toBe(temppayload.title);
+    expect(throws.length).toBe(1);
+
+    mynock
+      .persist()
+      .get(`/article-cooler/${temppayload.id}`)
+      .reply(200, { ...temppayload, title: 'othertitle' });
+
+    expect(throws.length).toBe(1);
+    await act(async () => {
+      await fetch(FutureArticleResource.delete, temppayload.id);
+      rerender({ id: null });
+    });
+    expect(throws.length).toBe(1);
+    expect(result.current[0]).toBe(null);
+  });
+});

