+        await act(async () => {
+          await controller.fetch(getValues.assign, {
+            added: {
+              id: 1,
+              title: 'newly assigned',
+            },
+          });
+        });
+
+        expect(result.current.added).toBeInstanceOf(Article);
+        expect(result.current.added).toMatchSnapshot();
+      });
+    },
+  );
+});

