+import {
+  CoolerArticleResource,
+  ArticleResource,
+  PaginatedArticleResource,
+  UserResource,
+  ArticleResourceWithOtherListUrl,
+} from '__tests__/common';
+import React from 'react';
+import nock from 'nock';
+import { act } from '@testing-library/react-hooks';
+
+// relative imports to avoid circular dependency in tsconfig references
+import { SimpleRecord } from '@rest-hooks/normalizr';
+
+import {
+  makeRenderRestHook,
+  makeCacheProvider,
+  makeExternalCacheProvider,
+} from '../../../../test';
+import { useResource, useFetcher, useCache } from '../hooks';
+import {
+  payload,
+  createPayload,
+  users,
+  nested,
+  paginatedFirstPage,
+  paginatedSecondPage,
+} from '../test-fixtures';
+
+function onError(e: any) {
+  e.preventDefault();
+}
+beforeEach(() => {
+  if (typeof addEventListener === 'function')
+    addEventListener('error', onError);
+});
+afterEach(() => {
+  if (typeof removeEventListener === 'function')
+    removeEventListener('error', onError);
+});
+
+for (const makeProvider of [makeCacheProvider, makeExternalCacheProvider]) {
+  describe(`${makeProvider.name} => <Provider />`, () => {
+    // TODO: add nested resource test case that has multiple partials to test merge functionality
+
+    let renderRestHook: ReturnType<typeof makeRenderRestHook>;
+    let mynock: nock.Scope;
+
+    beforeEach(() => {
+      nock(/.*/)
+        .persist()
+        .defaultReplyHeaders({
+          'Access-Control-Allow-Origin': '*',
+          'Content-Type': 'application/json',
+        })
+        .options(/.*/)
+        .reply(200)
+        .get(`/article-cooler/${payload.id}`)
+        .reply(200, payload)
+        .delete(`/article-cooler/${payload.id}`)
+        .reply(204, '')
+        .delete(`/article/${payload.id}`)
+        .reply(200, {})
+        .get(`/article-cooler/0`)
+        .reply(403, {})
+        .get(`/article-cooler/666`)
+        .reply(200, '')
+        .get(`/article-cooler/`)
+        .reply(200, nested)
+        .post(`/article-cooler/`)
+        .reply(200, createPayload)
+        .get(`/user/`)
+        .reply(200, users);
+      mynock = nock(/.*/).defaultReplyHeaders({
+        'Access-Control-Allow-Origin': '*',
+        'Content-Type': 'application/json',
+      });
+    });
+
+    afterEach(() => {
+      nock.cleanAll();
