pr_description:
### Motivation
<!--
Does this solve a bug? Enable a new use-case? Improve an existing behavior? Concrete examples are helpful here.
-->
Simpler installs - no longer need multiple extra packages. All react-related integrations in one package.

### Solution
<!--
What is the solution here from a high level. What are the key technical decisions and why were they made?
-->
Add [@data-client/react/redux](https://dataclient.io/docs/guides/redux)

```ts
import {
  ExternalDataProvider,
  prepareStore,
  type Middleware,
} from '@data-client/react/redux';
import { getDefaultManagers, Controller } from '@data-client/react';
import ReactDOM from 'react-dom';

const managers = getDefaultManagers();
// be sure to include your other reducers here
const otherReducers = {};
const extraMiddlewares: Middleware = [];

const { store, selector, controller } = prepareStore(
  initialState,
  managers,
  Controller,
  otherReducers,
  extraMiddlewares,
);

ReactDOM.render(
  <ExternalDataProvider
    store={store}
    selector={selector}
    controller={controller}
  >
    <App />
  </ExternalDataProvider>,
  document.body,
);
```

Mark [@data-client/redux](https://www.npmjs.com/package/@data-client/redux) as deprecated

