+    expect(result.current).toBe(undefined);
+    await waitForNextUpdate();
+    expect(result.current).toStrictEqual(response);
+  });
+});

diff --git a/packages/core/src/react-integration/provider/__tests__/provider.tsx b/packages/core/src/react-integration/provider/__tests__/provider.tsx
new file mode 100644
index 0000000..42acc1e
--- /dev/null
+++ b/packages/core/src/react-integration/provider/__tests__/provider.tsx
@@ -0,0 +1,74 @@
+import { CoolerArticleResource } from '__tests__/common';
+import { RECEIVE_TYPE } from '@rest-hooks/core/actionTypes';
+import React, { useContext } from 'react';
+import { act, render } from '@testing-library/react';
+
+import { DispatchContext, StateContext } from '../../context';
+import CacheProvider from '../CacheProvider';
+
+describe('<CacheProvider />', () => {
+  it('should not change dispatch function on re-render', () => {
+    let dispatch;
+    let count = 0;
+    function DispatchTester() {
+      dispatch = useContext(DispatchContext);
+      count++;
+      return null;
+    }
+    const chil = <DispatchTester />;
+    const tree = <CacheProvider>{chil}</CacheProvider>;
+    const { rerender } = render(tree);
+    expect(dispatch).toBeDefined();
+    let curDisp = dispatch;
+    rerender(tree);
+    expect(curDisp).toBe(dispatch);
+    expect(count).toBe(1);
+    rerender(<CacheProvider>{chil}</CacheProvider>);
+    expect(curDisp).toBe(dispatch);
+    expect(count).toBe(1);
+    const managers: any[] = [];
+    rerender(<CacheProvider managers={managers}>{chil}</CacheProvider>);
+    curDisp = dispatch;
+    rerender(<CacheProvider managers={managers}>{chil}</CacheProvider>);
+    expect(curDisp).toBe(dispatch);
+    expect(count).toBe(1);
+    rerender(
+      <DispatchContext.Provider value={() => Promise.resolve()}>
+        {chil}
+      </DispatchContext.Provider>,
+    );
+    expect(curDisp).not.toBe(dispatch);
+    expect(count).toBe(2);
+  });
+  it('should change state', () => {
+    let dispatch: any, state;
+    let count = 0;
+    function ContextTester() {
+      dispatch = useContext(DispatchContext);
+      state = useContext(StateContext);
+      count++;
+      return null;
+    }
+    const chil = <ContextTester />;
+    const tree = <CacheProvider>{chil}</CacheProvider>;
+    render(tree);
+    expect(dispatch).toBeDefined();
+    expect(state).toBeDefined();
+    const action = {
+      type: RECEIVE_TYPE,
+      payload: { id: 5, title: 'hi', content: 'more things here' },
+      meta: {
+        schema: CoolerArticleResource,
+        key: CoolerArticleResource.url({ id: 5 }),
+        mutate: false,
+        date: 50,
+        expiresAt: 55,
+      },
+    };
+    act(() => {
+      dispatch(action);
+    });
+    expect(count).toBe(2);
+    expect(state).toMatchSnapshot();
+  });
+});

