+        MyEntity {
+          "blarb": null,
+          "name": "bob",
+          "secondthing": "hi",
+        }
+      `);
+  });
+
+  test('denormalizes to undefined for deleted data', () => {
+    const entities = {
+      Menu: {
+        '1': { id: '1', food: '2' },
