+    }) {}
+    User.schema = {
+      reports: new schema.Array(Report),
+    };
+    class CommentData {
+      id = '';
+      readonly body: string = '';
+      readonly author: User = User.fromJS();
+    }
+    class Comment extends EntityMixin(CommentData, {
+      schema: { author: User },
