+          article: null,
+          requiredArticle: ArticleEntity.fromJS({ id: '5' }),
+          nextPage: 'blob',
+        });
+      });
+
+      it('should be marked as found when nested entity is missing', () => {
+        const denormalized = denormalize(WithOptional, 'abc', {
+          [WithOptional.key]: {
