+    'Content-Type': 'application/json',
+  });
+});
+
+afterAll(() => {
+  nock.cleanAll();
+});
+
+describe('useFetcher', () => {
+  const payload = { id: 1, content: 'hi' };
+
+  it('should dispatch an action that fetches a create', async () => {
+    mynock.post(`/article-cooler/`).reply(201, payload);
+
