+              ArticleResourceWithOtherListUrl.otherList(),
+              {},
+            );
+            return { create, listA, listB };
+          },
+          {
+            results: [
+              {
+                request: ArticleResourceWithOtherListUrl.otherList(),
+                params: {},
+                result: [{ id: 100, content: 'something' }],
+              },
+            ],
+          },
+        );
+
+        expect(result.current.listA).toEqual(undefined);
+        expect(result.current.listB).toEqual([existingItem]);
+
+        const promise = result.current.create({}, body, [
+          [
+            ArticleResourceWithOtherListUrl.list(),
+            {},
+            (newArticleID: string, articleIDs: string[] | undefined) => [
+              ...(articleIDs || []),
+              newArticleID,
+            ],
+          ],
+          [
+            ArticleResourceWithOtherListUrl.otherList(),
+            {},
+            (newArticleID: string, articleIDs: string[] | undefined) => [
+              ...(articleIDs || []),
+              newArticleID,
+            ],
+          ],
+        ]);
+
+        expect(result.current.listA).toEqual([
+          CoolerArticleResource.fromJS(body),
+        ]);
+        expect(result.current.listB).toEqual([
+          existingItem,
+          CoolerArticleResource.fromJS(body),
+        ]);
+        await promise;
+        expect(result.current.listA).toEqual([
+          CoolerArticleResource.fromJS({
+            ...payload,
+            title: 'some other title',
+            content: 'real response',
+          }),
+        ]);
+        expect(result.current.listB).toEqual([
+          existingItem,
+          CoolerArticleResource.fromJS({
+            ...payload,
+            title: 'some other title',
+            content: 'real response',
+          }),
+        ]);
+      });
+
+      it('should clear only earlier optimistic updates when a promise resolves', async () => {
+        jest.useFakeTimers();
+
+        const params = { id: payload.id };
+        const { result, waitForNextUpdate } = renderRestHook(
+          () => {
+            const put = useFetcher(CoolerArticleResource.partialUpdate());
+            const article = useCache(CoolerArticleResource.detail(), params);
+            return { put, article };
+          },
+          {
+            results: [
+              {
+                request: CoolerArticleResource.detail(),
+                params,
+                result: payload,
+              },
+            ],
+          },
+        );
+
+        // first optimistic
+        mynock
+          .patch('/article-cooler/5')
+          .delay(200)
+          .reply(200, {
+            ...payload,
+            title: 'first',
+            content: 'first',
+          });
+        result.current.put(params, {
+          title: 'firstoptimistic',
+          content: 'firstoptimistic',
+        });
+        expect(result.current.article).toEqual(
+          CoolerArticleResource.fromJS({
+            ...payload,
+            title: 'firstoptimistic',
+            content: 'firstoptimistic',
+          }),
+        );
+
+        // second optimistic
+        mynock
+          .patch('/article-cooler/5')
+          .delay(50)
+          .reply(200, {
+            ...payload,
+            title: 'second',
+          });
+        result.current.put(params, {
+          title: 'secondoptimistic',
+        });
+        expect(result.current.article).toEqual(
+          CoolerArticleResource.fromJS({
+            ...payload,
+            title: 'secondoptimistic',
+            content: 'firstoptimistic',
+          }),
+        );
+
+        // second optimistic
+        mynock
+          .patch('/article-cooler/5')
+          .delay(500)
+          .reply(200, {
+            ...payload,
+            tags: ['third'],
+          });
+        result.current.put(params, {
+          tags: ['thirdoptimistic'],
+        });
+        expect(result.current.article).toEqual(
+          CoolerArticleResource.fromJS({
+            ...payload,
+            title: 'secondoptimistic',
+            content: 'firstoptimistic',
+            tags: ['thirdoptimistic'],
+          }),
+        );
+
+        // resolve second request while first is in flight
+        jest.advanceTimersByTime(51);
+        await waitForNextUpdate();
+
+        // first and second optimistic should be cleared with only third optimistic left to be layerd
+        // on top of second's network response
+        expect(result.current.article).toEqual(
+          CoolerArticleResource.fromJS({
+            ...payload,
+            title: 'second',
+          }),
+        );
+      });
+
+      describe('indexes', () => {
+        it('should resolve parallel useResource() request', async () => {
+          const { result, waitForNextUpdate } = renderRestHook(() => {
+            useResource(IndexedUserResource.list(), {});
+            return {
+              bob: useCache(IndexedUserResource.index(), {
+                username: 'bob',
+              }),
+              charlie: useCache(IndexedUserResource.index(), {
+                username: 'charlie',
+              }),
+              fetch: useFetcher(IndexedUserResource.detail()),
+            };
+          });
+          expect(result.current).toBeNull();
+          await waitForNextUpdate();
+          const bob = result.current.bob;
+          expect(bob).toBeDefined();
+          expect(bob instanceof UserResource).toBe(true);
+          expect(bob?.username).toBe('bob');
+          expect(bob).toMatchSnapshot();
+          expect(result.current.charlie).toBeUndefined();
+
+          const renamed = { ...users[0] };
+          renamed.username = 'charlie';
+          mynock.get(`/user/23`).reply(200, renamed);
+          result.current.fetch({ id: '23' });
+          await waitForNextUpdate();
+
+          const charlie = result.current.charlie;
+          expect(charlie).toBeDefined();
+          expect(charlie instanceof UserResource).toBe(true);
+          expect(charlie?.username).toBe('charlie');
+          expect(charlie).toMatchSnapshot();
+          expect(result.current.bob).toBeUndefined();
+        });
+      });
+    });
+  });
+}

diff --git a/packages/core/src/react-integration/__tests__/useCache-endpoint.tsx b/packages/core/src/react-integration/__tests__/useCache-endpoint.tsx
new file mode 100644
index 0000000..29a8717
--- /dev/null
+++ b/packages/core/src/react-integration/__tests__/useCache-endpoint.tsx
@@ -0,0 +1,196 @@
+import {
+  CoolerArticleResource,
+  PaginatedArticleResource,
+  InvalidIfStaleArticleResource,
+  GetNoEntities,
+} from '__tests__/new';
+import React, { useEffect } from 'react';
+
+// relative imports to avoid circular dependency in tsconfig references
+import { makeRenderRestHook, makeCacheProvider } from '../../../../test';
+import { useCache } from '../hooks';
+import { articlesPages, payload } from '../test-fixtures';
+
+describe('useCache()', () => {
+  let renderRestHook: ReturnType<typeof makeRenderRestHook>;
+  beforeEach(() => {
+    renderRestHook = makeRenderRestHook(makeCacheProvider);
+  });
+  afterEach(() => {
+    renderRestHook.cleanup();
+  });
+
+  it('should be null with empty state', () => {
+    const { result } = renderRestHook(() => {
+      return useCache(CoolerArticleResource.detail(), payload);
+    }, {});
+    // @ts-expect-error
+    result.current?.doesnotexist;
+    expect(result.current).toBe(undefined);
+  });
+
+  it('should return undefined in entities slots when results are not found', async () => {
+    const userId = '5';
+    const { result } = renderRestHook(() => {
+      return useCache(GetNoEntities, { userId });
+    });
+    expect(result.current).toEqual({ firstThing: '', someItems: undefined });
+  });
+
+  it('should select singles', () => {
+    const results = [
+      {
+        request: CoolerArticleResource.detail(),
+        params: payload,
+        result: payload,
+      },
+    ];
+    const { result } = renderRestHook(
+      () => {
+        return useCache(CoolerArticleResource.detail(), payload);
+      },
+      { results },
+    );
+
+    expect(result.current).toBeTruthy();
+    expect(result.current?.title).toBe(payload.title);
+  });
+
+  it('should not select when results are stale and invalidIfStale is true', () => {
+    const realDate = global.Date.now;
+    Date.now = jest.fn(() => 999999999);
+    const results = [
+      {
+        request: InvalidIfStaleArticleResource.detail(),
+        params: payload,
+        result: payload,
+      },
+    ];
+    const { result, rerender } = renderRestHook(
+      props => {
+        return useCache(InvalidIfStaleArticleResource.detail(), props);
+      },
+      { results, initialProps: { id: payload.id } },
+    );
+
+    expect(result.current).toBeDefined();
+    Date.now = jest.fn(() => 999999999 * 3);
+
+    rerender({ id: payload.id * 2 });
+    expect(result.current).toBeUndefined();
+    rerender({ id: payload.id });
+    expect(result.current).toBeUndefined();
+
+    global.Date.now = realDate;
+  });
+
+  it('should select paginated results', () => {
+    const results = [
+      {
+        request: PaginatedArticleResource.list(),
+        params: {},
+        result: articlesPages,
+      },
+    ];
+    const { result } = renderRestHook(
+      () => {
+        return useCache(PaginatedArticleResource.list(), {});
+      },
+      { results },
+    );
+    expect(result.current).toBeDefined();
+    if (!result.current) return;
+    expect(result.current.results).toBeDefined();
+    if (!result.current.results) return;
+    expect(result.current.results.length).toBe(articlesPages.results.length);
+    expect(result.current.results[0]).toBeInstanceOf(PaginatedArticleResource);
+    expect(result.current.results).toMatchSnapshot();
+  });
+
+  it('should return identical value no matter how many re-renders', () => {
+    const results = [
+      {
+        request: PaginatedArticleResource.list(),
+        params: {},
+        result: articlesPages,
+      },
+    ];
+    const track = jest.fn();
+
+    const { rerender } = renderRestHook(
+      () => {
+        const articles = useCache(PaginatedArticleResource.list(), {});
+        useEffect(track, [articles]);
+      },
+      { results },
+    );
+
+    expect(track.mock.calls.length).toBe(1);
+    for (let i = 0; i < 2; ++i) {
+      rerender();
+    }
+    expect(track.mock.calls.length).toBe(1);
+  });
+
+  describe('Nested with defaults', () => {
+    it('should send defaults with nothing in state', () => {
+      const defaults = { prevPage: '', nextPage: '', results: undefined };
+      const { result } = renderRestHook(
+        () => {
+          return useCache(PaginatedArticleResource.list(), {});
+        },
+        { results: [] },
+      );
+      expect(result.current).toEqual(defaults);
+    });
+
+    it('should find results', () => {
+      const results = [
+        {
+          request: PaginatedArticleResource.list(),
+          params: {},
+          result: articlesPages,
+        },
+      ];
+      const { result } = renderRestHook(
+        () => {
+          return useCache(PaginatedArticleResource.list(), {});
+        },
+        { results },
+      );
+      expect(result.current).toBeTruthy();
+      expect(result.current.nextPage).toBe(articlesPages.nextPage);
+      expect(result.current.prevPage).toBe(articlesPages.prevPage);
+      expect(result.current.results).toEqual(
+        articlesPages.results.map(article =>
+          PaginatedArticleResource.fromJS(article),
+        ),
+      );
+    });
+
+    it('should return identical value no matter how many re-renders', () => {
+      const results = [
+        {
+          request: PaginatedArticleResource.list(),
+          params: {},
+          result: articlesPages,
+        },
+      ];
+      const track = jest.fn();
+
+      const { rerender } = renderRestHook(
+        () => {
+          useEffect(track, [results]);
+          return useCache(PaginatedArticleResource.list(), {});
+        },
+        { results },
+      );
+
+      expect(track.mock.calls.length).toBe(1);
+      for (let i = 0; i < 2; ++i) {
+        rerender();
+      }
+      expect(track.mock.calls.length).toBe(1);
+    });
+  });
+});

diff --git a/packages/core/src/react-integration/__tests__/useResource-endpoint.web.tsx b/packages/core/src/react-integration/__tests__/useResource-endpoint.web.tsx
new file mode 100644
index 0000000..d26f6b0
--- /dev/null
+++ b/packages/core/src/react-integration/__tests__/useResource-endpoint.web.tsx
@@ -0,0 +1,515 @@
+import {
+  CoolerArticleResource,
+  UserResource,
+  InvalidIfStaleArticleResource,
+  GetPhoto,
+  GetNoEntities,
+  ArticleTimedResource,
+} from '__tests__/new';
+import { State } from '@rest-hooks/core';
+import { initialState } from '@rest-hooks/core/state/reducer';
+import React, { Suspense } from 'react';
+import { render } from '@testing-library/react';
+import nock from 'nock';
+
+// relative imports to avoid circular dependency in tsconfig references
+
+import { normalize, SimpleRecord } from '@rest-hooks/normalizr';
+import { ReadEndpoint } from '@rest-hooks/endpoint';
+
+import {
+  makeRenderRestHook,
+  makeCacheProvider,
+  mockInitialState,
+} from '../../../../test';
+import { DispatchContext, StateContext } from '../context';
+import { useResource } from '../hooks';
+import { payload, users, nested } from '../test-fixtures';
+
+async function testDispatchFetch(
+  Component: React.FunctionComponent<any>,
+  payloads: any[],
+) {
+  const dispatch = jest.fn();
+  const tree = (
+    <DispatchContext.Provider value={dispatch}>
+      <Suspense fallback={null}>
+        <Component />
+      </Suspense>
+    </DispatchContext.Provider>
+  );
+  render(tree);
+  expect(dispatch).toHaveBeenCalled();
+  expect(dispatch.mock.calls.length).toBe(payloads.length);
+  let i = 0;
+  for (const call of dispatch.mock.calls) {
+    expect(call[0]).toMatchSnapshot();
+    const action = call[0];
+    const res = await action.payload();
+    expect(res).toEqual(payloads[i]);
+    i++;
+  }
+}
+
+function ArticleComponentTester({ invalidIfStale = false }) {
+  const resource = invalidIfStale
+    ? InvalidIfStaleArticleResource
+    : CoolerArticleResource;
+  const article = useResource(resource.detail(), {
+    id: payload.id,
+  });
+  return (
+    <div>
+      <h3>{article.title}</h3>
+      <p>{article.content}</p>
+    </div>
+  );
+}
+
+describe('useResource()', () => {
+  let renderRestHook: ReturnType<typeof makeRenderRestHook>;
+  const fbmock = jest.fn();
+
+  async function testMalformedResponse(
+    payload: any,
+    endpoint: ReadEndpoint = CoolerArticleResource.detail(),
+  ) {
+    nock(/.*/)
+      .persist()
+      .defaultReplyHeaders({
+        'Access-Control-Allow-Origin': '*',
+        'Content-Type': 'application/json',
+      })
+      .get(`/article-cooler/400`)
+      .reply(200, payload);
+
+    const { result, waitForNextUpdate } = renderRestHook(() => {
+      return useResource(endpoint as any, {
+        id: 400,
+      });
+    });
+    expect(result.current).toBe(null);
+    await waitForNextUpdate();
+    expect(result.error).toBeDefined();
+    expect((result.error as any).status).toBeGreaterThan(399);
+    expect(result.error).toMatchSnapshot();
+  }
+
+  function Fallback() {
+    fbmock();
+    return null;
+  }
+
+  beforeAll(() => {
+    nock(/.*/)
+      .persist()
+      .defaultReplyHeaders({
+        'Access-Control-Allow-Origin': '*',
+        'Content-Type': 'application/json',
+      })
+      .options(/.*/)
+      .reply(200)
+      .get(`/article-cooler/${payload.id}`)
+      .reply(200, payload)
+      .get(`/article-time/${payload.id}`)
+      .reply(200, { ...payload, createdAt: '2020-06-07T02:00:15+0000' })
+      .delete(`/article-cooler/${payload.id}`)
+      .reply(204, '')
+      .delete(`/article/${payload.id}`)
+      .reply(200, {})
+      .get(`/article-cooler/0`)
+      .reply(403, {})
+      .get(`/article-cooler/666`)
+      .reply(200, '')
+      .get(`/article-cooler/`)
+      .reply(200, nested)
+      .get(`/user/`)
+      .reply(200, users);
+  });
+
+  afterAll(() => {
+    nock.cleanAll();
+  });
+
+  beforeEach(() => {
+    renderRestHook = makeRenderRestHook(makeCacheProvider);
+  });
+  afterEach(() => {
+    renderRestHook.cleanup();
+  });
+
+  it('should dispatch an action that fetches', async () => {
+    await testDispatchFetch(ArticleComponentTester, [payload]);
+  });
+
+  it('should dispatch fetch when sent multiple arguments', async () => {
+    function MultiResourceTester() {
+      const [article, user] = useResource(
+        [
+          CoolerArticleResource.detail(),
+          {
+            id: payload.id,
+          },
+        ],
+        [UserResource.list(), {}],
+      );
+      return null;
+    }
+    await testDispatchFetch(MultiResourceTester, [payload, users]);
+  });
+  it('should throw same promise until both resolve', async () => {
+    const renderRestHook = makeRenderRestHook(makeCacheProvider);
+    jest.useFakeTimers();
+    nock('http://test.com')
+      .get(`/article-cooler/${payload.id}`)
+      .delay(1000)
+      .reply(200, payload);
+    nock('http://test.com').get(`/user/`).delay(2000).reply(200, users);
+
+    function MultiResourceTester() {
+      try {
+        const [article, user] = useResource(
+          [
+            CoolerArticleResource.detail(),
+            {
+              id: payload.id,
+            },
+          ],
+          [UserResource.list(), {}],
+        );
+        return article;
+      } catch (e) {
+        // TODO: we're not handling suspense properly so react complains
+        // When upgrading test util we should be able to fix this as we'll suspense ourselves.
+        if (typeof e.then === 'function') {
+          return e;
+        } else {
+          throw e;
+        }
+      }
+    }
+    const { rerender, result } = renderRestHook(MultiResourceTester);
+    const firstPromise = result.current;
+    expect(firstPromise).toBeDefined();
+    expect(typeof firstPromise.then).toBe('function');
+
+    jest.advanceTimersByTime(50);
+    rerender();
+    expect(result.current).toBe(firstPromise);
+    jest.advanceTimersByTime(1000);
+    rerender();
+    expect(result.current).toBe(firstPromise);
+    jest.advanceTimersByTime(2000);
+    rerender();
+    expect(result.current).toBe(firstPromise);
+
+    // TODO: we're not handling suspense properly so react complains
+    // When upgrading test util we should be able to fix this as we'll suspense ourselves.
+    const oldError = console.error;
+    console.error = () => {};
+    jest.runAllTimers();
+    await result.current;
+    rerender();
+    expect(result.current).toMatchInlineSnapshot(`
+      CoolerArticleResource {
+        "author": null,
+        "content": "whatever",
+        "id": 5,
+        "tags": Array [
+          "a",
+          "best",
+          "react",
+        ],
+        "title": "hi ho",
+      }
+    `);
+    // eslint-disable-next-line require-atomic-updates
+    console.error = oldError;
+  });
+  it('should NOT suspend if result already in cache and options.invalidIfStale is false', () => {
+    const state: State<unknown> = mockInitialState([
+      {
+        request: CoolerArticleResource.detail(),
+        params: payload,
+        result: payload,
+      },
+    ]) as any;
+
+    const tree = (
+      <StateContext.Provider value={state}>
+        <Suspense fallback={<Fallback />}>
+          <ArticleComponentTester />
+        </Suspense>
+      </StateContext.Provider>
+    );
+    const { getByText } = render(tree);
+    expect(fbmock).not.toBeCalled();
+    const title = getByText(payload.title);
+    expect(title).toBeDefined();
+    expect(title.tagName).toBe('H3');
+  });
+  it('should NOT suspend even when result is stale and options.invalidIfStale is false', () => {
+    const { entities, result } = normalize(payload, CoolerArticleResource);
+    const fetchKey = CoolerArticleResource.detail().getFetchKey(payload);
+    const state = {
+      ...initialState,
+      entities,
+      results: {
+        [fetchKey]: result,
+      },
+      meta: {
+        [fetchKey]: {
+          date: 0,
+          expiresAt: 0,
+        },
+      },
+    };
+
+    const tree = (
+      <StateContext.Provider value={state}>
+        <DispatchContext.Provider value={() => Promise.resolve()}>
+          <Suspense fallback={<Fallback />}>
+            <ArticleComponentTester />
+          </Suspense>{' '}
+        </DispatchContext.Provider>
+      </StateContext.Provider>
+    );
+    const { getByText } = render(tree);
+    expect(fbmock).not.toBeCalled();
+    const title = getByText(payload.title);
+    expect(title).toBeDefined();
+    expect(title.tagName).toBe('H3');
+  });
+  it('should NOT suspend if result is not stale and options.invalidIfStale is true', () => {
+    const { entities, result } = normalize(
+      payload,
+      InvalidIfStaleArticleResource,
+    );
+    const fetchKey = InvalidIfStaleArticleResource.detail().getFetchKey(
+      payload,
+    );
+    const state = {
+      ...initialState,
+      entities,
+      results: {
+        [fetchKey]: result,
+      },
+      meta: {
+        [fetchKey]: {
+          date: Infinity,
+          expiresAt: Infinity,
+        },
+      },
+    };
+
+    const tree = (
+      <StateContext.Provider value={state}>
+        <Suspense fallback={<Fallback />}>
+          <ArticleComponentTester invalidIfStale />
+        </Suspense>
+      </StateContext.Provider>
+    );
+    const { getByText } = render(tree);
+    expect(fbmock).not.toBeCalled();
+    const title = getByText(payload.title);
+    expect(title).toBeDefined();
+    expect(title.tagName).toBe('H3');
+  });
+  it('should suspend if result stale in cache and options.invalidIfStale is true', () => {
+    const { entities, result } = normalize(
+      payload,
+      InvalidIfStaleArticleResource,
+    );
+    const fetchKey = InvalidIfStaleArticleResource.detail().getFetchKey(
+      payload,
+    );
+    const state = {
+      ...initialState,
+      entities,
+      results: {
+        [fetchKey]: result,
+      },
+      meta: {
+        [fetchKey]: {
+          date: 0,
+          expiresAt: 0,
+        },
+      },
+    };
+
+    const tree = (
+      <StateContext.Provider value={state}>
+        <DispatchContext.Provider value={() => Promise.resolve()}>
+          <Suspense fallback={<Fallback />}>
+            <ArticleComponentTester invalidIfStale />
+          </Suspense>
+        </DispatchContext.Provider>
+      </StateContext.Provider>
+    );
+    render(tree);
+    expect(fbmock).toHaveBeenCalled();
+  });
+
+  // taken from integration
+  it('should throw errors on bad network', async () => {
+    const { result, waitForNextUpdate } = renderRestHook(() => {
+      return useResource(CoolerArticleResource.detail(), {
+        title: '0',
+      });
+    });
+    expect(result.current).toBe(null);
+    await waitForNextUpdate();
+    expect(result.error).toBeDefined();
+    expect((result.error as any).status).toBe(403);
+  });
+
+  it('should throw errors on bad network (multiarg)', async () => {
+    const { result, waitForNextUpdate } = renderRestHook(() => {
+      return useResource([
+        CoolerArticleResource.detail(),
+        {
+          title: '0',
+        },
+      ]);
+    });
+    expect(result.current).toBe(null);
+    await waitForNextUpdate();
+    expect(result.error).toBeDefined();
+    expect((result.error as any).status).toBe(403);
+  });
+
+  it('should throw error when response is array when expecting entity', async () => {
+    await testMalformedResponse([]);
+  });
+
+  it('should throw error when response is {} when expecting entity', async () => {
+    await testMalformedResponse({});
+  });
+
+  it('should throw error when response is number when expecting entity', async () => {
+    await testMalformedResponse(5);
+  });
+
+  it('should throw error when response is string when expecting entity', async () => {
+    await testMalformedResponse('hi');
+  });
+
+  it('should throw error when response is string when expecting nested entity', async () => {
+    const endpoint = CoolerArticleResource.detail().extend({
+      schema: { data: CoolerArticleResource },
+    });
+    await testMalformedResponse('hi', endpoint);
+  });
+
+  it('should throw error when response is nested string when expecting nested entity', async () => {
+    const endpoint = CoolerArticleResource.detail().extend({
+      schema: { data: CoolerArticleResource },
+    });
+    await testMalformedResponse({ data: 5, parcel: 2 }, endpoint);
+  });
+
+  it('should throw error when response is nested missing id when expecting nested entity', async () => {
+    const endpoint = CoolerArticleResource.detail().extend({
+      schema: { data: CoolerArticleResource },
+    });
+    await testMalformedResponse(
+      { data: { ...payload, id: undefined }, parcel: 2 },
+      endpoint,
+    );
+  });
+
+  it('should throw error when response is expected Resource inside Record', async () => {
+    class Scheme extends SimpleRecord {
+      data: CoolerArticleResource = CoolerArticleResource.fromJS();
+      optional: UserResource | null = null;
+      static schema = {
+        data: CoolerArticleResource,
+        optional: UserResource,
+      };
+    }
+    const endpoint = CoolerArticleResource.detail().extend({
+      schema: Scheme,
+    });
+    await testMalformedResponse({ data: null }, endpoint);
+  });
+
+  it('should resolve parallel useResource() request', async () => {
+    const { result, waitForNextUpdate } = renderRestHook(() => {
+      return useResource(
+        [
+          CoolerArticleResource.detail(),
+          {
+            id: payload.id,
+          },
+        ],
+        [UserResource.list(), {}],
+      );
+    });
+    await waitForNextUpdate();
+    const [article, users] = result.current;
+    expect(article instanceof CoolerArticleResource).toBe(true);
+    expect(article.title).toBe(payload.title);
+    expect(users).toBeDefined();
+    expect(users.length).toBeTruthy();
+    expect(users[0] instanceof UserResource).toBe(true);
+  });
+
+  it('should not suspend with no params to useResource()', () => {
+    let article: any;
+    const { result } = renderRestHook(() => {
+      article = useResource(CoolerArticleResource.detail(), null);
+      return 'done';
+    });
+    expect(result.current).toBe('done');
+    expect(article).toBeUndefined();
+  });
+
+  it('should work with shapes with no entities', async () => {
+    const userId = '5';
+    const response = { firstThing: '', someItems: [{ a: 5 }] };
+    nock(/.*/)
+      .defaultReplyHeaders({ 'access-control-allow-origin': '*' })
+      .get(`/users/${userId}/simple`)
+      .reply(200, response);
+    const { result, waitForNextUpdate } = renderRestHook(() => {
+      return useResource(GetNoEntities, { userId });
+    });
+    // null means it threw
+    expect(result.current).toBe(null);
+    await waitForNextUpdate();
+    expect(result.current).toStrictEqual(response);
+  });
+
+  it('should work with ArrayBuffer shapes', async () => {
+    const userId = '5';
+    const response = new ArrayBuffer(10);
+    nock(/.*/)
+      .defaultReplyHeaders({ 'access-control-allow-origin': '*' })
+      .get(`/users/${userId}/photo`)
+      .reply(200, response);
+    const { result, waitForNextUpdate } = renderRestHook(() => {
+      return useResource(GetPhoto, { userId });
+    });
+    // null means it threw
+    expect(result.current).toBe(null);
+    await waitForNextUpdate();
+    expect(result.current).toStrictEqual(response);
+  });
+
+  it('should work with Serializable shapes', async () => {
+    const { result, waitForNextUpdate } = renderRestHook(() => {
+      return useResource(ArticleTimedResource.detail(), payload);
+    });
+    // null means it threw
+    expect(result.current).toBe(null);
+    await waitForNextUpdate();
+    expect(result.current.createdAt.getDate()).toBe(
+      result.current.createdAt.getDate(),
+    );
+    expect(result.current.createdAt).toEqual(
+      new Date('2020-06-07T02:00:15+0000'),
+    );
+    expect(result.current.id).toEqual(payload.id);
+    expect(result.current).toBeInstanceOf(ArticleTimedResource);
+  });
+});

