+      const text = '<body>this is html</body>';
+      nock(/.*/)
+        .defaultReplyHeaders({
+          'Access-Control-Allow-Origin': '*',
+        })
+        .get(`/article-cooler/${id}`)
+        .reply(200, text, {});
+
+      const res = await CoolerArticleResource.fetch(
+        CoolerArticleResource.url({ id }),
+        { method: 'GET' },
+      );
+      expect(res).toBe(text);
+    });
+
+    it('should use getFetchInit if defined', async () => {
+      class FetchResource extends CoolerArticleResource {
+        static getFetchInit = jest.fn(a => a);
+      }
+      const article = await FetchResource.detail();
+      expect(article).toBeDefined();
+      expect(FetchResource.getFetchInit.mock.calls.length).toBeGreaterThan(0);
+    });
+  });
+
+  describe('nested schema', () => {
+    describe('merging', () => {
+      const nested = [
+        {
+          id: 5,
+          title: 'hi ho',
+          content: 'whatever',
+          tags: ['a', 'best', 'react'],
+          author: {
+            id: 23,
+            username: 'bob',
+            email: 'bob@bob.com',
+          },
+        },
+        {
+          id: 3,
+          title: 'the next time',
+          content: 'whatever',
+          author: {
+            id: 23,
+            username: 'charles',
+          },
+        },
+      ];
+      const { schema } = CoolerArticleResource.listWithUser();
+      const normalized = normalize(nested, schema);
+
+      // TODO: fix normalize types so we know this is actuaally multiple things
+      const user: any = normalized.entities[UserResource.key]['23'];
+      it('should include nested user', () => {
+        expect(user).toBeDefined();
+      });
+      it('should have user be UserResource type', () => {
+        expect(user).toBeInstanceOf(UserResource);
+      });
+      it('should take property of first if not set in second', () => {
+        expect(user.email).toBe('bob@bob.com');
+      });
+      it('should overwrite second properties over first', () => {
+        expect(user.username).toBe('charles');
+      });
+      it('should use default for unset propreties', () => {
+        expect(UserResource.hasDefined(user, 'isAdmin')).toBe(false);
+      });
+      it('should match snapshot', () => {
+        expect(normalized).toMatchSnapshot();
+      });
+    });
+
+    it('should throw a custom error if data does not include pk', () => {
+      const schema = CoolerArticleResource;
+      function normalizeBad() {
+        normalize({ content: 'hi' }, schema);
+      }
+      expect(normalizeBad).toThrowErrorMatchingSnapshot();
+    });
+  });
+});

pr_description:
### Motivation
<!--
Does this solve a bug? Enable a new use-case? Improve an existing behavior? Concrete examples are helpful here.
-->
Authentication with context requires running some code each time endpoints are called. Do we need to construct the full endpoints then?

### Solution
<!--
What is the solution here from a high level. What are the key technical decisions and why were they made?
-->
Still memoize endpoints, but provide `runInit()` member that is run everytime the endpoint method is called. Collapsing this into the memoization function also makes the definitions more terse. Also make customizing methods easier, with a method member for endpoints.

Newly added:

- runInit()
- method

Also make memo method a protected member so it can be used to memoize other extensions.

#### Added auth test case using

Useful for #273

```typescript
export const AuthContext = createContext('');

export class ContextAuthdArticle extends ArticleResource {
  /** Init options for fetch */
  static getFetchInit(init: RequestInit): RequestInit {
    /* eslint-disable-next-line */
    const accessToken = useContext(AuthContext);
    return {
      ...init,
      headers: {
        ...init.headers,
        'Access-Token': accessToken,
      },
    };
  }
}
```

