+        {
+          wrapper,
+          initialProps: { authToken: '' },
+        },
+      );
+      // null means it threw (suspended)
+      expect(result.current).toBe(null);
+      await waitForNextUpdate();
+      expect(result.current.data.title).toBe('unauthorized');
+      rerender({ authToken: 'thepassword' });
+      const data = await result.current.fetch(payload);
+      expect(data).toEqual(payload);
+      expect(result.current.data.title).toEqual(payload.title);
+    });
+  });
 });

pr_description:
Fixes #337

### Motivation
<!--
Does this solve a bug? Enable a new use-case? Improve an existing behavior? Concrete examples are helpful here.
-->
Cancellation can be powerful

### Solution
<!--
What is the solution here from a high level. What are the key technical decisions and why were they made?
-->
- Do not register abort errors
```
    // In case we abort simply undo the optimistic update and act like no fetch even occured
    // We still want those watching promises from fetch directly to observed the abort, but we don't want to
    // Trigger errors in this case. This means theoretically improperly built abortes useResource() could suspend forever.
```
- Add `signal` member to Resource endpoint's for easy integration
 ```typescript
const abort = new AbortController();
const AbortableArticle = CoolerArticleResource.detail().extend({
  signal: abort.signal,
});
// ...somewhere later trigger cancellation
abort.abort();
```

#### Full Resource.endpoint definition

```typescript
  protected static endpoint() {
    return this.memo('#endpoint', () => {
      // eslint-disable-next-line
      const self = this;
      const instanceFetch = this.fetch.bind(this);
      const url = this.url.bind(this);

      return new Endpoint(
        function (params: Readonly<object>) {
          return instanceFetch(this.url(params), this.getFetchInit());
        },
        {
          ...this.getEndpointExtra(),
          key: function (this: any, params: Readonly<object>) {
            return `${this.method} ${this.url(params)}`;
          },
          url,
          fetchInit: {} as RequestInit,
          // this runs at endpoint calltime, so can possibly use hooks
          useFetchInit(this: any) {
            this.fetchInit = self.getFetchInit(this.fetchInit);
            return this;
          },
          // this runs at fetch calltime
          getFetchInit(
            this: any,
            body?: RequestInit['body'] | Record<string, any>,
          ) {
            if (isPojo(body)) {
              body = JSON.stringify(body);
            }
            return {
              ...this.fetchInit,
              method: this.method,
              signal: this.signal,
              body,
            };
          },
          method: 'GET',
          signal: undefined as AbortSignal | undefined,
        },
      );
    });
  }
```

