+          f: 0,
+          g: 0,
+          h: 0,
+          i: 0,
+          j: 0,
+          k: 0,
+          l: 0,
+          m: 0,
+          n: 0,
+          o: 0,
+          p: 0,
+          q: 0,
+          r: 0,
+          s: 0,
+          t: 0,
+          u: 0,
+        },
+        schema,
+      ),
+    ).toMatchSnapshot();
+    expect(consoleOutput.length).toBe(0);
+  });
+
+  it('should not expect getters returned', () => {
+    class MyEntity extends Entity {
