+      }
+
+      pk() {
+        return this.name;
+      }
+    }
+    function normalizeBad() {
+      normalize({ name: 'hoho', nonexistantthing: 'hi' }, MyEntity);
+    }
+    expect(normalizeBad).toThrow();
+  });
+
+  it('should throw if data loads with unexpected prop that is a method', () => {
+    class MyEntity extends Entity {
