+      readonly secondthing: string = '';
+      readonly thirdthing: number = 0;
+      readonly thirdthing2: number = 0;
+
+      nonexistantthing() {
+        return this.name + 5;
+      }
+
+      nonexistantthing2() {
+        return this.name + 5;
+      }
+
+      nonexistantthing3() {
+        return this.name + 5;
+      }
+
+      nonexistantthing4() {
+        return this.name + 5;
+      }
+
+      pk() {
+        return this.name;
+      }
+    }
+    function normalizeBad() {
