diff --git a/packages/legacy/src/resource/__tests__/Delete.test.ts b/packages/legacy/src/resource/__tests__/Delete.test.ts
new file mode 100644
index 0000000..4d304a0
--- /dev/null
+++ b/packages/legacy/src/resource/__tests__/Delete.test.ts
@@ -0,0 +1,88 @@
+// eslint-env jest
+import { fromJS } from 'immutable';
+import { normalize, schema, denormalize, DELETED } from '@rest-hooks/normalizr';
+
+import IDEntity from '../IDEntity';
+import Entity from '../Entity';
+
+let dateSpy: jest.SpyInstance;
+beforeAll(() => {
+  dateSpy = jest
+    // eslint-disable-next-line no-undef
+    .spyOn(global.Date, 'now')
+    .mockImplementation(() => new Date('2019-05-14T11:01:58.135Z').valueOf());
+});
+afterAll(() => {
+  dateSpy.mockRestore();
+});
+
+describe(`${schema.Delete.name} normalization`, () => {
+  test('throws if not given an entity', () => {
+    // @ts-expect-error
+    expect(() => new schema.Delete()).toThrow();
+  });
+
+  test('normalizes an object', () => {
+    class User extends IDEntity {}
+
+    expect(
+      normalize({ id: '1', type: 'users' }, new schema.Delete(User)),
+    ).toMatchSnapshot();
+  });
+
+  it('should throw a custom error if data does not include pk', () => {
+    class MyEntity extends Entity {
+      readonly name: string = '';
+      readonly secondthing: string = '';
+      pk() {
+        return this.name;
+      }
+    }
+    function normalizeBad() {
+      normalize({ secondthing: 'hi' }, new schema.Delete(MyEntity));
+    }
+    expect(normalizeBad).toThrowErrorMatchingSnapshot();
+  });
+});
+
+describe(`${schema.Union.name} denormalization`, () => {
+  class User extends IDEntity {
+    readonly username: string = '';
+    readonly type: string = '';
+  }
+  const entities = {
+    User: {
+      '1': User.fromJS({ id: '1', username: 'Janey', type: 'users' }),
+    },
+  };
+
+  test('denormalizes an object in the same manner as the Entity', () => {
+    const [user, ready, deleted] = denormalize(
+      '1',
+      new schema.Delete(User),
+      entities,
+    );
+    expect(user).toBeDefined();
+    expect(user).toBeInstanceOf(User);
+    expect(user?.username).toBe('Janey');
+    expect(ready).toBe(true);
+    expect(deleted).toBe(false);
+  });
+
+  test('denormalizes deleted entities as undefined', () => {
+    const [user, ready, deleted] = denormalize('1', new schema.Delete(User), {
+      User: { '1': DELETED },
+    });
+    expect(user).toBe(undefined);
+    expect(ready).toBe(true);
+    expect(deleted).toBe(true);
+
+    expect(
+      denormalize(
+        { data: '1' },
+        { data: new schema.Delete(User) },
+        fromJS({ User: { '1': DELETED } }),
+      ),
+    ).toMatchSnapshot();
+  });
+});

diff --git a/packages/legacy/src/resource/__tests__/Entity.test.ts b/packages/legacy/src/resource/__tests__/Entity.test.ts
new file mode 100644
index 0000000..76e2f4d
--- /dev/null
+++ b/packages/legacy/src/resource/__tests__/Entity.test.ts
@@ -0,0 +1,1012 @@
+// eslint-env jest
+import { fromJS, Record } from 'immutable';
+import {
+  normalize,
+  schema,
+  denormalize,
+  DELETED,
+  AbstractInstanceType,
+  WeakListMap,
+} from '@rest-hooks/normalizr';
+
+import SimpleRecord from '../SimpleRecord';
+import IDEntity from '../IDEntity';
+import Entity from '../Entity';
+
+let dateSpy: jest.SpyInstance;
+beforeAll(() => {
+  dateSpy = jest
+    // eslint-disable-next-line no-undef
+    .spyOn(global.Date, 'now')
+    .mockImplementation(() => new Date('2019-05-14T11:01:58.135Z').valueOf());
+});
+afterAll(() => {
+  dateSpy.mockRestore();
+});
+
+const values = obj => Object.keys(obj).map(key => obj[key]);
+
+class Tacos extends IDEntity {
+  readonly name: string = '';
+  readonly alias: string | undefined = undefined;
+}
+
+class ArticleEntity extends Entity {
+  readonly id: string = '';
+  readonly title: string = '';
+  readonly author: string = '';
+  readonly content: string = '';
+  pk() {
+    return this.id;
+  }
+}
+
+class WithOptional extends Entity {
+  readonly id: string = '';
+  readonly article: ArticleEntity | null = null;
+  readonly requiredArticle = ArticleEntity.fromJS();
+  readonly nextPage: string = '';
+
+  pk() {
+    return this.id;
+  }
+
+  static schema = {
+    article: ArticleEntity,
+    requiredArticle: ArticleEntity,
+  };
+}
+
+describe(`${Entity.name} normalization`, () => {
+  const originalWarn = console.warn;
+  afterEach(() => {
+    console.warn = originalWarn;
+    consoleOutput = [];
+  });
+  let consoleOutput: string[] = [];
+  const mockedWarn = (output: string) => {
+    consoleOutput.push(output);
+  };
+  beforeEach(() => (console.warn = mockedWarn));
+
+  test('normalizes an entity', () => {
+    class MyEntity extends IDEntity {}
+    expect(normalize({ id: '1' }, MyEntity)).toMatchSnapshot();
+  });
+
+  it('should throw a custom error if data does not include pk', () => {
+    class MyEntity extends Entity {
+      readonly name: string = '';
+      readonly secondthing: string = '';
+      pk() {
+        return this.name;
+      }
+    }
+    const schema = MyEntity;
+    function normalizeBad() {
