+        readonly type: string = '';
+
+        static schema = {
+          data: { attachment: AttachmentsEntity },
+        };
+
+        static fromJS<T extends typeof SimpleRecord>(
+          this: T,
+          props: Partial<AbstractInstanceType<T>>,
+          parent?: any,
+          key?: string,
+        ) {
+          return super.fromJS({
+            ...values(props)[0],
+            type: Object.keys(props)[0],
+          }) as AbstractInstanceType<T>;
+        }
+      }
