+      });
+      expect(denormalized[1]).toBe(true);
+      expect(denormalized[2]).toBe(true);
+      const response = denormalized[0];
+      expect(response).toBeDefined();
+      expect(response).toBeInstanceOf(WithOptional);
+      expect(response).toEqual({
+        id: 'abc',
+        article: null,
+        requiredArticle: undefined,
+        nextPage: 'blob',
+      });
+    });
+
+    it('should be non-required deleted members should not result in deleted indicator', () => {
+      const denormalized = denormalize('abc', WithOptional, {
+        [WithOptional.key]: {
+          abc: WithOptional.fromJS({
+            id: 'abc',
+            // this is typed because we're actually sending wrong data to it
+            article: '5' as any,
+            requiredArticle: '6' as any,
+            nextPage: 'blob',
+          }),
+        },
+        [ArticleEntity.key]: {
+          ['5']: DELETED,
+          ['6']: ArticleEntity.fromJS({ id: '6' }),
+        },
+      });
+      expect(denormalized[1]).toBe(true);
+      expect(denormalized[2]).toBe(false);
+      const response = denormalized[0];
+      expect(response).toBeDefined();
+      expect(response).toBeInstanceOf(WithOptional);
+      expect(response).toEqual({
+        id: 'abc',
+        article: undefined,
+        requiredArticle: ArticleEntity.fromJS({ id: '6' }),
+        nextPage: 'blob',
+      });
+    });
+
+    it('should be both deleted and not found when both are true in different parts of schema', () => {
+      const denormalized = denormalize(
+        { data: 'abc' },
+        { data: WithOptional, other: ArticleEntity },
+        {
+          [WithOptional.key]: {
+            abc: WithOptional.fromJS({
+              id: 'abc',
+              // this is typed because we're actually sending wrong data to it
+              article: '6' as any,
+              requiredArticle: '5' as any,
+              nextPage: 'blob',
+            }),
+          },
+          [ArticleEntity.key]: {
+            ['5']: DELETED,
+            ['6']: ArticleEntity.fromJS({ id: '6' }),
+          },
+        },
+      );
+      expect(denormalized[1]).toBe(false);
+      expect(denormalized[2]).toBe(true);
+      const response = denormalized[0];
+      expect(response).toBeDefined();
+      expect(response).toEqual({
+        data: {
+          id: 'abc',
+          article: ArticleEntity.fromJS({ id: '6' }),
+          requiredArticle: undefined,
+          nextPage: 'blob',
+        },
+      });
+    });
+  });
+});

diff --git a/packages/legacy/src/resource/__tests__/SimpleRecord.test.ts b/packages/legacy/src/resource/__tests__/SimpleRecord.test.ts
new file mode 100644
index 0000000..40301e0
--- /dev/null
+++ b/packages/legacy/src/resource/__tests__/SimpleRecord.test.ts
@@ -0,0 +1,324 @@
+import { denormalize, normalize, DELETED } from '@rest-hooks/normalizr';
+
+import { Entity, SimpleRecord } from '..';
+
+let dateSpy: jest.SpyInstance;
+beforeAll(() => {
+  dateSpy = jest
+    // eslint-disable-next-line no-undef
+    .spyOn(global.Date, 'now')
+    .mockImplementation(() => new Date('2019-05-14T11:01:58.135Z').valueOf());
+});
+afterAll(() => {
+  dateSpy.mockRestore();
+});
+
+class Article extends SimpleRecord {
+  readonly id: string = '';
+  readonly title: string = '';
+  readonly author: string = '';
+  readonly content: string = '';
+}
+class ArticleEntity extends Entity {
+  readonly id: string = '';
+  readonly title: string = '';
+  readonly author: string = '';
+  readonly content: string = '';
+  pk() {
+    return this.id;
+  }
+}
+
+class Pagination extends SimpleRecord {
+  readonly data = ArticleEntity.fromJS();
+  readonly nextPage: string = '';
+  readonly lastPage: string = '';
+
+  get title() {
+    return this.data.title;
+  }
+
+  static schema = {
+    data: ArticleEntity,
+  };
+}
+
+class WithOptional extends SimpleRecord {
+  readonly article: ArticleEntity | null = null;
+  readonly requiredArticle = ArticleEntity.fromJS();
+  readonly nextPage = '';
+  readonly createdAt: Date | null = null;
+
+  static schema = {
+    article: ArticleEntity,
+    requiredArticle: ArticleEntity,
+    createdAt: Date,
+  };
+}
+
+describe('SimpleRecord', () => {
+  it('should init', () => {
+    const resource = Article.fromJS({
+      id: '5',
+      title: 'happy',
+      author: '5',
+    });
+    expect(resource.title).toBe('happy');
+    expect(resource.author).toBe('5');
+  });
+
+  it('should not allow init with wrong types', () => {
+    Article.fromJS({
+      // @ts-expect-error
+      id: 5,
+      title: 'happy',
+      // @ts-expect-error
+      author: 5,
+    });
+  });
+
+  describe('normalize', () => {
+    it('should normalize into plain object', () => {
+      const schema = Article;
+      const normalized = normalize(
+        {
+          id: '5',
+          title: 'happy',
+          author: '5',
+        },
+        schema,
+      );
+      expect(normalized.result).toEqual({
+        id: '5',
+        title: 'happy',
+        author: '5',
+      });
+    });
+
+    it('should work on nested', () => {
+      const schema = Pagination;
+      const normalized = normalize(
+        {
+          data: {
+            id: '5',
+            title: 'happy',
+            author: '5',
+          },
+          lastPage: 'abc',
+          nextPage: 'slksfd',
+        },
+        schema,
+      );
+      expect(normalized).toMatchSnapshot();
+    });
+
+    it('should deserialize Date', () => {
+      const normalized = normalize(
+        {
+          requiredArticle: { id: '5' },
+          nextPage: 'blob',
+          createdAt: '2020-06-07T02:00:15.000Z',
+        },
+        WithOptional,
+      );
+      expect(normalized.result.createdAt.getTime()).toBe(
+        normalized.result.createdAt.getTime(),
+      );
+      expect(normalized).toMatchSnapshot();
+    });
+
+    it('should use default when Date not provided', () => {
+      const normalized = normalize(
+        {
+          requiredArticle: { id: '5' },
+          nextPage: 'blob',
+        },
+        WithOptional,
+      );
+      expect(normalized.result.createdAt).toBeUndefined();
+      expect(normalized).toMatchSnapshot();
+    });
+  });
+
+  describe('denormalize', () => {
+    it('should denormalize with defaults', () => {
+      const schema = Article;
+      const denormalized = denormalize(
+        {
+          id: '5',
+          title: 'happy',
+          author: '5',
+        },
+        schema,
+        {},
+      );
+      const article = denormalized[0];
+      expect(article).toBeDefined();
+      expect(article).toBeInstanceOf(Article);
+      expect(article).toEqual({
+        id: '5',
+        title: 'happy',
+        author: '5',
+        content: '',
+      });
+      // typing of members that it has
+      article?.content;
+      article?.author;
+      // @ts-expect-error - fails when it doesn't
+      article?.bob;
+    });
+
+    it('should work with nested and default correctly', () => {
+      const schema = Pagination;
+      const denormalized = denormalize(
+        {
+          data: '5',
+          nextPage: 'blob',
+        },
+        schema,
+        {
+          [ArticleEntity.key]: {
+            ['5']: {
+              id: '5',
+              title: 'happy',
+              author: '5',
+            },
+          },
+        },
+      );
+      expect(denormalized[1]).toBe(true);
+      const pagination = denormalized[0];
+      expect(pagination).toBeDefined();
+      expect(pagination).toBeInstanceOf(Pagination);
+      expect(pagination).toEqual({
+        data: {
+          id: '5',
+          title: 'happy',
+          author: '5',
+          content: '',
+        },
+        nextPage: 'blob',
+        lastPage: '',
+      });
+      // check getters
+      expect(pagination.title).toBe('happy');
+      // typing of members that it has
+      pagination.data?.content;
+      pagination.data?.title;
+      // @ts-expect-error - data might be undefined since its a nested entity
+      pagination.data.content;
+      // @ts-expect-error - fails when it doesn't have member
+      pagination?.bob;
+    });
+  });
+
+  it('should have undefined member when entity is not found', () => {
+    const schema = Pagination;
+    const denormalized = denormalize(
+      {
+        data: '5',
+        nextPage: 'blob',
+      },
+      schema,
+      {},
+    );
+    expect(denormalized[1]).toBe(false);
+    const pagination = denormalized[0];
+    expect(pagination).toBeDefined();
+    expect(pagination).toBeInstanceOf(Pagination);
+    expect(pagination).toEqual({
+      data: undefined,
+      nextPage: 'blob',
+      lastPage: '',
+    });
+  });
+
+  describe('optional entities', () => {
+    it('should be marked as found even when optional is not there', () => {
+      const denormalized = denormalize(
+        {
+          requiredArticle: '5',
+          nextPage: 'blob',
+          createdAt: new Date('2020-06-07T02:00:15+0000'),
+        },
+        WithOptional,
+        {
+          [ArticleEntity.key]: {
+            5: ArticleEntity.fromJS({ id: '5' }),
+          },
+        },
+      );
+      expect(denormalized[1]).toBe(true);
+      const response = denormalized[0];
+      expect(response).toBeDefined();
+      expect(response).toBeInstanceOf(WithOptional);
+      expect(response).toEqual({
+        article: null,
+        requiredArticle: ArticleEntity.fromJS({ id: '5' }),
+        nextPage: 'blob',
+        createdAt: new Date('2020-06-07T02:00:15+0000'),
+      });
+      // @ts-expect-error
+      response.createdAt.toISOString();
+      expect(response.createdAt?.toISOString()).toBe(
+        '2020-06-07T02:00:15.000Z',
+      );
+    });
+
+    it('should be marked as not found when required entity is missing', () => {
+      const denormalized = denormalize(
+        {
+          article: '5',
+          nextPage: 'blob',
+        },
+        WithOptional,
+        {
+          [ArticleEntity.key]: {
+            5: ArticleEntity.fromJS({ id: '5' }),
+          },
+        },
+      );
+      expect(denormalized[1]).toBe(false);
+      expect(denormalized[2]).toBe(false);
+      const response = denormalized[0];
+      expect(response).toBeDefined();
+      expect(response).toBeInstanceOf(WithOptional);
+      expect(response).toEqual({
+        article: ArticleEntity.fromJS({ id: '5' }),
+        requiredArticle: ArticleEntity.fromJS(),
+        nextPage: 'blob',
+        createdAt: null,
+      });
+      expect(response.createdAt).toBeNull();
+    });
+
+    it('should be marked as deleted when required entity is deleted symbol', () => {
+      const denormalized = denormalize(
+        {
+          article: '5',
+          requiredArticle: '6',
+          nextPage: 'blob',
+        },
+        WithOptional,
+        {
+          [ArticleEntity.key]: {
+            5: ArticleEntity.fromJS({ id: '5' }),
+            6: DELETED,
+          },
+        },
+      );
+      expect(denormalized[1]).toBe(true);
+      expect(denormalized[2]).toBe(true);
+      const response = denormalized[0];
+      expect(response).toBeDefined();
+      expect(response).toBeInstanceOf(WithOptional);
+      expect(response).toEqual({
+        article: ArticleEntity.fromJS({ id: '5' }),
+        requiredArticle: undefined,
+        nextPage: 'blob',
+        createdAt: null,
+      });
+      expect(response.createdAt).toBeNull();
+    });
+  });
+});

diff --git a/packages/legacy/src/resource/__tests__/normalizr.test.js b/packages/legacy/src/resource/__tests__/normalizr.test.js
new file mode 100644
index 0000000..8946a12
--- /dev/null
+++ b/packages/legacy/src/resource/__tests__/normalizr.test.js
@@ -0,0 +1,998 @@
+// eslint-env jest
+import { fromJS } from 'immutable';
+import {
+  denormalize,
+  normalize,
+  DELETED,
+  WeakListMap,
+} from '@rest-hooks/normalizr';
+
+import Entity from '../Entity';
+import IDEntity from '../IDEntity';
+
+class Tacos extends IDEntity {
+  type = '';
+}
+
+let dateSpy;
+beforeAll(() => {
+  dateSpy = jest
+    // eslint-disable-next-line no-undef
+    .spyOn(global.Date, 'now')
+    .mockImplementation(() => new Date('2019-05-14T11:01:58.135Z').valueOf());
+});
+afterAll(() => {
+  dateSpy.mockRestore();
+});
+
+describe('normalize', () => {
+  [42, null, undefined, '42', () => {}].forEach(input => {
+    test(`cannot normalize input that == ${input}`, () => {
+      class Test extends IDEntity {}
+      expect(() => normalize(input, Test)).toThrow();
+    });
+  });
+
+  test('passthrough with undefined schema', () => {
+    const input = {};
+    expect(normalize(input).result).toBe(input);
+  });
+
+  test('cannot normalize with null input', () => {
+    expect(() => normalize(null, Tacos)).toThrow(/null/);
+  });
+
+  test('can normalize string', () => {
+    const mySchema = '';
+    expect(normalize('bob', mySchema)).toMatchInlineSnapshot(`
+      Object {
+        "entities": Object {},
+        "entityMeta": Object {},
+        "indexes": Object {},
+        "result": "bob",
+      }
+    `);
+  });
+
+  test('normalizes entities', () => {
+    expect(
+      normalize(
+        [
+          { id: '1', type: 'foo' },
+          { id: '2', type: 'bar' },
+        ],
+        [Tacos],
+      ),
+    ).toMatchSnapshot();
+  });
+
+  test('normalizes schema with extra members', () => {
+    expect(
+      normalize(
+        {
+          data: [
+            { id: '1', type: 'foo' },
+            { id: '2', type: 'bar' },
+          ],
+          extra: 'five',
+          page: {
+            first: null,
+            second: { thing: 'two' },
+            third: 1,
+            complex: { complex: false, next: true },
+          },
+        },
+        {
+          data: [Tacos],
+          extra: '',
+          page: {
+            first: null,
+            second: undefined,
+            third: 0,
+            complex: { complex: true, next: false },
+          },
+        },
+      ),
+    ).toMatchSnapshot();
+  });
+
+  test('normalizes schema with extra members but not set', () => {
+    expect(
+      normalize(
+        {
+          data: [
+            { id: '1', type: 'foo' },
+            { id: '2', type: 'bar' },
+          ],
+        },
+        {
+          data: [Tacos],
+          extra: '',
+          page: {
+            first: null,
+            second: undefined,
+            third: 0,
+            complex: { complex: true, next: false },
+          },
+        },
+      ),
+    ).toMatchSnapshot();
+  });
+
+  test('normalizes schema with indexes', () => {
+    class MyTaco extends Tacos {
+      static indexes = ['type'];
+    }
+
+    expect(
+      normalize(
+        {
+          data: [
+            { id: '1', type: 'foo' },
+            { id: '2', type: 'bar' },
+          ],
+          alt: { id: '2', type: 'bar2' },
+        },
+        { data: [MyTaco], alt: MyTaco },
+      ),
+    ).toMatchSnapshot();
+  });
+
+  test('normalizes warns on schemas with unfound indexes', () => {
+    const oldError = console.warn;
+    const spy = (console.warn = jest.fn());
+
+    class MyTaco extends Tacos {
+      static indexes = ['notfound'];
+    }
+
+    expect(
+      normalize(
+        {
+          data: [
+            { id: '1', type: 'foo' },
+            { id: '2', type: 'bar' },
+          ],
+          alt: { id: '2', type: 'bar2' },
+        },
+        { data: [MyTaco], alt: MyTaco },
+      ),
+    ).toMatchSnapshot();
+
+    expect(spy.mock.calls[0]).toMatchInlineSnapshot(`
+      Array [
+        "Index not found in entity. Indexes must be top-level members of your entity.
+      Index: notfound
+      Entity: {
+        \\"id\\": \\"1\\",
+        \\"type\\": \\"foo\\"
+      }",
+      ]
+    `);
+    console.warn = oldError;
+  });
+
+  test('normalizes entities with circular references', () => {
+    class User extends IDEntity {}
+    User.schema = { friends: [User] };
+
+    const input = { id: '123', friends: [] };
+    input.friends.push(input);
+
+    expect(normalize(input, User)).toMatchSnapshot();
+  });
+
+  test('normalizes nested entities', () => {
+    class User extends IDEntity {}
+    class Comment extends IDEntity {
+      comment = '';
+      static schema = {
+        user: User,
+      };
+    }
+    class Article extends IDEntity {
+      title = '';
+      body = '';
+      static schema = {
+        author: User,
+        comments: [Comment],
+      };
+    }
+
+    const input = {
+      id: '123',
+      title: 'A Great Article',
+      author: {
+        id: '8472',
+        name: 'Paul',
+      },
+      body: 'This article is great.',
+      comments: [
+        {
+          id: 'comment-123-4738',
+          comment: 'I like it!',
+          user: {
+            id: '10293',
+            name: 'Jane',
+          },
+        },
+      ],
+    };
+    expect(normalize(input, Article)).toMatchSnapshot();
+  });
+
+  test('does not modify the original input', () => {
+    class User extends IDEntity {}
+    class Article extends IDEntity {
+      title = '';
+      static schema = {
+        author: User,
+      };
+    }
+    const input = Object.freeze({
+      id: '123',
+      title: 'A Great Article',
+      author: Object.freeze({
+        id: '8472',
+        name: 'Paul',
+      }),
+    });
+    expect(() => normalize(input, Article)).not.toThrow();
+  });
+
+  test('ignores null values', () => {
+    class MyEntity extends IDEntity {}
+    expect(normalize([null], [MyEntity])).toMatchSnapshot();
+    expect(normalize([undefined], [MyEntity])).toMatchSnapshot();
+    expect(normalize([false], [MyEntity])).toMatchSnapshot();
+  });
+
+  test('can use fully custom entity classes', () => {
+    class Children extends IDEntity {
+      name = '';
+    }
+    class MyEntity extends Entity {
+      uuid = '';
+      name = '';
+
+      static schema = {
+        children: [Children],
+      };
+
+      pk() {
+        return this.uuid;
+      }
+
+      static normalize(input, parent, key, visit, addEntity, visitedEntities) {
+        const entity = { ...input };
+        Object.keys(this.schema).forEach(key => {
+          const schema = this.schema[key];
+          entity[key] = visit(
+            input[key],
+            input,
+            key,
+            schema,
+            addEntity,
+            visitedEntities,
+          );
+        });
+        addEntity(this, entity, this.pk(entity));
+        return {
+          uuid: this.pk(entity),
+          schema: this.key,
+        };
+      }
+    }
+
+    class Food extends MyEntity {}
+    expect(
+      normalize(
+        {
+          uuid: '1234',
+          name: 'tacos',
+          children: [{ id: 4, name: 'lettuce' }],
+        },
+        Food,
+      ),
+    ).toMatchSnapshot();
+  });
+
+  test('uses the non-normalized input when getting the ID for an entity', () => {
+    const calls = [];
+    class User extends IDEntity {}
+    class Recommendations extends Entity {
+      pk(parent, key) {
+        calls.push([this, parent, key]);
+        return parent.user.id;
+      }
+
+      static schema = { user: User };
+    }
+
+    expect(
+      normalize({ user: { id: '456' } }, Recommendations),
+    ).toMatchSnapshot();
+    expect(calls).toMatchSnapshot();
+  });
+
+  test('passes over pre-normalized values', () => {
+    class User extends IDEntity {}
+    class Article extends IDEntity {
+      title = '';
+      static schema = { author: User };
+    }
+
+    expect(
+      normalize(
+        { id: '123', title: 'normalizr is great!', author: '1' },
+        Article,
+      ),
+    ).toMatchSnapshot();
+
+    expect(normalize({ user: '1' }, { user: User })).toMatchSnapshot();
+  });
+
+  test('can normalize object without proper object prototype inheritance', () => {
+    const test = { id: '1', elements: [] };
+    test.elements.push(
+      Object.assign(Object.create(null), {
+        id: '18',
+        name: 'test',
+      }),
+    );
+
+    class Elements extends IDEntity {}
+    class Test extends IDEntity {
+      static schema = {
+        elements: [Elements],
+      };
+    }
+
+    expect(() => normalize(test, Test)).not.toThrow();
+  });
+});
+
+describe('denormalize', () => {
+  test('passthrough with undefined schema', () => {
+    const input = {};
+    expect(denormalize(input)).toStrictEqual([input, true, false, {}]);
+  });
+
+  test('returns the input if undefined', () => {
+    expect(denormalize(undefined, {}, {})).toEqual([
+      undefined,
+      false,
+      false,
+      {},
+    ]);
+  });
+
+  test('returns the input if string', () => {
+    expect(denormalize('bob', '', {})).toEqual(['bob', true, false, {}]);
+  });
+
+  test('denormalizes entities', () => {
+    const entities = {
+      Tacos: {
+        1: { id: '1', type: 'foo' },
+        2: { id: '2', type: 'bar' },
+      },
+    };
+    expect(denormalize(['1', '2'], [Tacos], entities)[0]).toMatchSnapshot();
+  });
+
+  test('denormalizes without entities fills undefined', () => {
+    expect(denormalize({ data: '1' }, { data: Tacos }, {})).toMatchSnapshot();
+    expect(
+      denormalize(fromJS({ data: '1' }), { data: Tacos }, {}),
+    ).toMatchSnapshot();
+    expect(denormalize('1', Tacos, {})).toEqual([undefined, false, false, {}]);
+  });
+
+  test('denormalizes ignoring unfound entities in arrays', () => {
+    const entities = {
+      Tacos: {
+        1: { id: '1', type: 'foo' },
+      },
+    };
+    expect(denormalize(['1', '2'], [Tacos], entities)).toMatchSnapshot();
+    expect(
+      denormalize({ results: ['1', '2'] }, { results: [Tacos] }, entities),
+    ).toMatchSnapshot();
+  });
+
+  test('denormalizes ignoring deleted entities in arrays', () => {
+    const entities = {
+      Tacos: {
+        1: { id: '1', type: 'foo' },
+        2: DELETED,
+      },
+    };
+    expect(denormalize(['1', '2'], [Tacos], entities)).toMatchSnapshot();
+    expect(
+      denormalize({ results: ['1', '2'] }, { results: [Tacos] }, entities),
+    ).toMatchSnapshot();
+  });
+
+  test('denormalizes arrays with objects inside', () => {
+    const entities = {
+      Tacos: {
+        1: { id: '1', type: 'foo' },
+      },
+    };
+    /*expect(
+      denormalize([{ data: 1 }, { data: 2 }], [{ data: Tacos }], {})[0],
+    ).toEqual([]);*/
+    expect(
+      denormalize([{ data: 1 }, { data: 2 }], [{ data: Tacos }], entities)[0],
+    ).toMatchSnapshot();
+  });
+
+  test('denormalizes schema with extra members', () => {
