+
+describe('denormalize with global cache', () => {
+  test('maintains referential equality with same results', () => {
+    const entityCache = {};
+    const resultCache = new WeakListMap();
+    const entities = {
+      Tacos: {
+        1: { id: '1', type: 'foo' },
+        2: { id: '2', type: 'bar' },
+      },
+    };
+    const result = ['1', '2'];
+    const [first] = denormalize(
+      result,
+      [Tacos],
+      entities,
+      entityCache,
+      resultCache,
+    );
+    const [second] = denormalize(
+      result,
+      [Tacos],
+      entities,
+      entityCache,
+      resultCache,
+    );
+    expect(first).toBe(second);
+
+    const [third] = denormalize(
+      [...result],
+      [Tacos],
+      entities,
+      entityCache,
+      resultCache,
+    );
+    expect(first).not.toBe(third);
+    expect(first).toEqual(third);
+
+    const fourth = denormalize(
+      result,
+      [Tacos],
+      { Tacos: { ...entities.Tacos, 2: { id: '2', type: 'bar' } } },
+      entityCache,
+      resultCache,
+    )[0];
+    expect(first).not.toBe(fourth);
+    expect(first).toEqual(fourth);
+  });
+
+  describe('nested entities', () => {
+    class User extends IDEntity {}
+    class Comment extends IDEntity {
+      comment = '';
+      static schema = {
+        user: User,
+      };
+    }
+    class Article extends IDEntity {
+      title = '';
+      body = '';
+      static schema = {
+        author: User,
+        comments: [Comment],
+      };
+    }
+
+    const entities = {
+      Article: {
+        123: {
+          author: '8472',
+          body: 'This article is great.',
+          comments: ['comment-123-4738'],
+          id: '123',
+          title: 'A Great Article',
+        },
+      },
+      Comment: {
+        'comment-123-4738': {
+          comment: 'I like it!',
+          id: 'comment-123-4738',
+          user: '10293',
+        },
+      },
+      User: {
+        10293: {
+          id: '10293',
+          name: 'Jane',
+        },
+        8472: {
+          id: '8472',
+          name: 'Paul',
+        },
+      },
+    };
+
+    test('maintains referential equality with nested entities', () => {
+      const entityCache = {};
+      const resultCache = new WeakListMap();
+
+      const result = { data: '123' };
+      const first = denormalize(
+        result,
+        { data: Article },
+        entities,
+        entityCache,
+        resultCache,
+      )[0];
+      const second = denormalize(
+        result,
+        { data: Article },
+        entities,
+        entityCache,
+        resultCache,
+      )[0];
+      expect(first).toBe(second);
+      const third = denormalize(
+        '123',
+        Article,
+        entities,
+        entityCache,
+        resultCache,
+      )[0];
+      const fourth = denormalize(
+        '123',
+        Article,
+        entities,
+        entityCache,
+        resultCache,
+      )[0];
+      expect(third).toBe(fourth);
+    });
+
+    test('entity equality changes', () => {
+      const entityCache = {};
+      const resultCache = new WeakListMap();
+
+      const result = { data: '123' };
+      const [first] = denormalize(
+        result,
+        { data: Article },
+        entities,
+        entityCache,
+        resultCache,
+      );
+      const [second] = denormalize(
+        result,
+        { data: Article },
+        {
+          ...entities,
+          Article: {
+            123: {
+              author: '8472',
+              body: 'This article is great.',
+              comments: ['comment-123-4738'],
+              id: '123',
+              title: 'A Great Article',
+            },
+          },
+        },
+        entityCache,
+        resultCache,
+      );
+      expect(first).not.toBe(second);
+      expect(first.data.author).toBe(second.data.author);
+      expect(first.data.comments[0]).toBe(second.data.comments[0]);
+    });
+  });
+
+  test('denormalizes plain object with no entities', () => {
+    const entityCache = {};
+    const resultCache = new WeakListMap();
+
+    const input = {
+      firstThing: { five: 5, seven: 42 },
+      secondThing: { cars: 'fifo' },
+    };
+    const [first, found, deleted] = denormalize(
+      input,
+      {
+        firstThing: { five: 0, seven: 0 },
+        secondThing: { cars: '' },
+      },
+      {},
+      entityCache,
+      resultCache,
+    );
+    expect(first).toEqual(input);
+    expect(found).toBe(true);
+    expect(deleted).toBe(false);
+    // should maintain referential equality
+    const [second] = denormalize(
+      input,
+      {
+        firstThing: { five: 0, seven: 0 },
+        secondThing: { cars: '' },
+      },
+      {},
+      {},
+      resultCache,
+    );
+    expect(second).toBe(first);
+  });
+
+  test('passthrough for null schema and an object input', () => {
+    const entityCache = {};
+    const resultCache = new WeakListMap();
+
+    const input = {
+      firstThing: { five: 5, seven: 42 },
+      secondThing: { cars: 'never' },
+    };
+    const [denorm, found, deleted] = denormalize(
+      input,
+      null,
+      {},
+      entityCache,
+      resultCache,
+    );
+    expect(denorm).toBe(input);
+    expect(found).toBe(true);
+    expect(deleted).toBe(false);
+  });
+
+  test('passthrough for null schema and an number input', () => {
+    const entityCache = {};
+    const resultCache = new WeakListMap();
+
+    const input = 5;
+    const [denorm, found, deleted] = denormalize(
+      input,
+      null,
+      {},
+      entityCache,
+      resultCache,
+    );
+    expect(denorm).toBe(input);
+    expect(found).toBe(true);
+    expect(deleted).toBe(false);
+  });
+
+  test('passthrough for undefined schema and an object input', () => {
+    const entityCache = {};
+    const resultCache = new WeakListMap();
+
+    const input = {
+      firstThing: { five: 5, seven: 42 },
+      secondThing: { cars: 'never' },
+    };
+    const [denorm, found, deleted] = denormalize(
+      input,
+      undefined,
+      {},
+      entityCache,
+      resultCache,
+    );
+    expect(denorm).toBe(input);
+    expect(found).toBe(true);
+    expect(deleted).toBe(false);
+  });
+
+  describe('null inputs when expecting entities', () => {
+    class User extends IDEntity {}
+    class Comment extends IDEntity {
+      comment = '';
+      static schema = {
+        user: User,
+      };
+    }
+    class Article extends IDEntity {
+      title = '';
+      body = '';
+      author = User.fromJS({});
+      comments = [];
+      static schema = {
+        author: User,
+        comments: [Comment],
+      };
+    }
+
+    test('handles null at top level', () => {
+      const entityCache = {};
+      const resultCache = new WeakListMap();
+
+      const [denorm, found, deleted] = denormalize(
+        null,
+        { data: Article },
+        {},
+        entityCache,
+        resultCache,
+      );
+      expect(denorm).toEqual({});
+      expect(found).toBe(false);
+      expect(deleted).toBe(false);
+    });
+
+    test('handles null in nested place', () => {
+      const entityCache = {};
+      const resultCache = new WeakListMap();
+
+      const input = {
+        data: { id: '5', title: 'hehe', author: null, comments: [] },
+      };
+      const [denorm, found, deleted] = denormalize(
+        input,
+        { data: Article },
+        {},
+        entityCache,
+        resultCache,
+      );
+      expect(denorm).toMatchInlineSnapshot(`
+        Object {
+          "data": Article {
+            "author": null,
+            "body": "",
+            "comments": Array [],
+            "id": "5",
+            "title": "hehe",
+          },
+        }
+      `);
+      expect(found).toBe(true);
+      expect(deleted).toBe(false);
+    });
+  });
+});

